-- One-time backfill: collapse synonymous glossary terms into single
-- multi-answer questions on already-seeded data. Safe to run more than once.
-- Run migration 0006 first (this also adds the column defensively).
--
-- Deleting the duplicate rows cascades to their card_progress/drill_responses,
-- so only progress on the merged-away duplicates is lost; everything else is kept.

alter table public.questions
  add column if not exists accepted_answers text[] not null default '{}';

begin;
-- Drilling
update public.questions set question = '[Drilling] To unscrew drillstring components downhole. The drillstring, including drillpipe and the bottomhole assembly, are coupled by various threadforms known as connections, or tool joints. Often, when a drillstring becomes stuck, it is necessary to "[TERM]" the string as deep as possible to recover as much of the string as possible. To facilitate the fishing or recovery operation, the [TERM] is usually accomplished by applying reverse torque and detonating an explosive charge inside a selected threaded connection. The force of the explosion enlarges the female (outer) thread enough that the threaded connection unscrews instantly. A torqueless [TERM] may be performed as well. In that case, tension is applied, and the threads slide by each other without turning when the explosive detonates. Backing off can also occur unintentionally.', accepted_answers = array['back off', 'backoff']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'backoff';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'backoff' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('back off'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('back off');
update public.questions set question = '1. (n.) [Drilling] Another term for [TERM], the intentional pumping of wellbore fluids down the annulus and back up through the drillpipe. This is the opposite of the normal direction of fluid circulation in a wellbore. Since the inside volume of the drillpipe is considerably less than the volume of the annulus outside of the drillpipe, [TERM] can bring bottomhole fluids to the surface faster than normal circulation for a given flow rate. Two potential hazards of [TERM] include lifting cuttings and other junk into the drillstring and the rapid flow of reservoir fluids to the surface in a kick situation. | 2. (vb.) [Well Completions] To conduct [TERM]—that is, to circulate fluid down the wellbore annulus, with returns being made up the tubing string. [TERM] is often used to remove debris from the wellbore because the high fluid flow rate inside the tubing string enables the recovery of large or dense debris particles that are difficult or impossible to remove with conventional circulation.', accepted_answers = array['back wash', 'backwash', 'reverse circulation', 'reversing out']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'backwash';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'backwash' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('back wash', 'reverse circulation', 'reversing out'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('back wash', 'reverse circulation', 'reversing out');
update public.questions set question = '[Drilling] An average or baseline measure of gas entrained in circulating mud. This baseline trend pertains to gas that is liberated downhole while drilling through a uniform lithologic interval at a constant rate of penetration. The gas is typically obtained from a suction line above the gas trap located immediately upstream of the shale shaker screens, where the gas evolves out of the mud. Oil-based mud systems tend to produce higher [TERM] values than do water-based muds. Deviations from the [TERM] trend likely indicate changes in porosity or permeability, or changes in drilling conditions; any of which merits further investigation. A drift or gradual shift of the [TERM] trend toward higher values may indicate a slow gas influx into the mud column, which can eventually lead to a kick or blowout. When annotated on mud logs, [TERM] is usually abbreviated as [TERM].', accepted_answers = array['background gas', 'BGG']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'BGG';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'BGG' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('background gas'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('background gas');
update public.questions set question = '1. (n.) [Drilling, Well Completions] The temperature of the undisturbed formation at the final depth in a well. The formation cools during drilling, and most of the cooling dissipates after about 24 hours of static conditions, although it is theoretically impossible for the temperature to return to undisturbed conditions. This temperature is measured under static conditions after sufficient time has elapsed to negate any effects from circulating fluids. Tables, charts, and computer routines are used to predict [TERM] as functions of depth, geographic area, and various time functions. The [TERM] is generally higher than the bottomhole circulating temperature and can be an important factor when using temperature-sensitive tools or treatments. | 2. (n.) [Drilling Fluids] The undisturbed temperature at the bottom of a well, abbreviated as [TERM]. After circulation and after the well is shut in, the temperature approaches the [TERM] after about 24 to 36 hours, depending on the well conditions. The [TERM] is the temperature used in most tests in which the cement slurry is required to set or is set.', accepted_answers = array['BHST', 'bottomhole static temperature']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'BHST';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'BHST' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('bottomhole static temperature'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('bottomhole static temperature');
update public.questions set question = '[Drilling] The process of pulling the drillstring out of the wellbore for the purpose of changing a worn or underperforming drill bit. Upon reaching the surface, the bit is usually inspected and graded on the basis of how worn the teeth are, whether it is still in gauge and whether its components are still intact. On drilling reports, this trip may be abbreviated as [TERM] (trip for new bit).', accepted_answers = array['bit trip', 'TFNB']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'TFNB';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'TFNB' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('bit trip'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('bit trip');
update public.questions set question = '[Drilling] An uncontrolled flow of reservoir fluids into the wellbore, and sometimes catastrophically to the surface. A [TERM] may consist of salt water, oil, gas, or a mixture of these. [TERM] occur in all types of exploration and production operations, not just during drilling operations. If reservoir fluids flow into another formation and do not flow to the surface, the result is called an underground [TERM]. If the well experiencing a [TERM] has significant openhole intervals, it is possible that the well will bridge over (or seal itself with rock fragments from collapsing formations) downhole and intervention efforts will be averted.', accepted_answers = array['blow out', 'blowout']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'blowout';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'blowout' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('blow out'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('blow out');
update public.questions set question = '[Drilling] The process of unscrewing drillstring components, which are coupled by various threadforms known as connections, including tool joints and other threaded connections.', accepted_answers = array['break out', 'breakout']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'breakout';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'breakout' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('break out'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('break out');
update public.questions set question = '[Drilling] The adapter between the first casing string and either the BOP stack (during drilling) or the wellhead (after completion). This adapter may be threaded or welded onto the casing, and may have a flanged or clamped connection to match the BOP stack or wellhead.', accepted_answers = array['casing head', 'casinghead']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'casinghead';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'casinghead' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('casing head'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('casing head');
update public.questions set question = '[Drilling] A relatively thin cable used with other equipment to move small rig and drillstring components and to provide tension on the tongs for tightening or loosening threaded connections.', accepted_answers = array['cat line', 'catline']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'catline';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'catline' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('cat line'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('cat line');
update public.questions set question = '[Drilling] Another term for [TERM], a rubber plug used to separate the cement slurry from other fluids, reducing contamination and maintaining predictable slurry performance. Two types of [TERM] are typically used on a cementing operation. The bottom plug is launched ahead of the cement slurry to minimize contamination by fluids inside the casing prior to cementing. A diaphragm in the plug body ruptures to allow the cement slurry to pass through after the plug reaches the landing collar. The top plug has a solid body that provides positive indication of contact with the landing collar and bottom plug through an increase in pump pressure.', accepted_answers = array['cementing plug', 'wiper plug']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'wiper plug';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'wiper plug' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('cementing plug'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('cementing plug');
update public.questions set question = '1. (n.) [Drilling] A long, continuous length of pipe wound on a spool. The pipe is straightened prior to pushing into a wellbore and rewound to coil the pipe back onto the transport and storage spool. Depending on the pipe diameter (1 in. to 4-1/2 in.) and the spool size, [TERM] can range from 2,000 ft to 15,000 ft [610 to 4,570 m] or greater length. For more details, The Defining Series: Introduction to [TERM]. | 2. (n.) [Well Workover and Intervention] A generic term relating to the use of a [TERM] string and associated equipment. As a well-intervention method, [TERM] techniques offer several key benefits over alternative well-intervention technologies. The ability to work safely under live well conditions, with a continuous string, enables fluids to be pumped at any time regardless of the position or direction of travel. This is a significant advantage in many applications. Installing an electrical conductor or hydraulic conduit further enhances the capability of a [TERM] string and enables relatively complex intervention techniques to be applied safely. For more details, see The Defining Series: Introduction to [TERM].', accepted_answers = array['coiled tubing', 'CT', 'endless tubing', 'reeled tubing']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'CT';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'CT' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('coiled tubing', 'endless tubing', 'reeled tubing'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('coiled tubing', 'endless tubing', 'reeled tubing');
update public.questions set question = '[Drilling] A method for recovering wireline stuck in a wellbore. In cut-and-thread operations, the wireline is gripped securely with a special tool and cut at the surface. The cut end is threaded through a stand of drillpipe. While the pipe hangs in the wellbore, the wireline is threaded through another stand of drillpipe, which is screwed onto the stand in the wellbore. The process is repeated until the stuck wireline is recovered. This technique, while dangerous and time-consuming, is known to improve greatly the chances of full recovery of the wireline and the tool at its end in the shortest overall time compared with trying to grab the wireline in the openhole with fishing tools.', accepted_answers = array['cut and thread fishing technique', 'cut-and-thread fishing technique']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'cut and thread fishing technique';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'cut and thread fishing technique' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('cut-and-thread fishing technique'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('cut-and-thread fishing technique');
update public.questions set question = '1. (n.) [Drilling] Also known as [TERM], a condition whereby the drillstring cannot be moved (rotated or reciprocated) along the axis of the wellbore. [TERM] typically occurs when high-contact forces caused by low reservoir pressures, high wellbore pressures, or both, are exerted over a sufficiently large area of the drillstring. [TERM] is, for most drilling organizations, the greatest drilling problem worldwide in terms of time and financial cost. It is important to note that the sticking force is a product of the differential pressure between the wellbore and the reservoir and the area that the differential pressure is acting upon. This means that a relatively low differential pressure (delta p) applied over a large working area can be just as effective in sticking the pipe as can a high differential pressure applied over a small area. | 2. (n.) [Drilling Fluids] A situation in which the drilling assembly (pipe, drill collars and bottomhole assembly) is stuck in filter cake that was previously deposited on a permeable zone. The pipe is held in the cake by a difference in pressures between the hydrostatic pressure of the mud and the pore pressure in the permeable zone. The force required to pull the pipe free can exceed the strength of the pipe. Methods used to get the pipe free, in addition to pulling and torquing the pipe, include: (1) lowering hydrostatic pressure in the wellbore, (2) placing a spotting fluid next to the stuck zone and (3) applying shock force just above the stuck point by mechanical jarring, or (4) all the above. The most common approach, however, to getting free is to place a spot of oil, oil-base mud, or special spotting fluid.', accepted_answers = array['differential sticking', 'wall sticking']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'wall sticking';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'wall sticking' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('differential sticking'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('differential sticking');
update public.questions set question = '[Drilling] Abbreviation for [TERM]. Mobil Oil Company first used this term in the early 1980s for drilling directional wells in which the drilled horizontal reach (HR) attained at total depth (TD) exceeded the true vertical depth (TVD) by a factor greater than or equal to two. [TERM] ([TERM]) is particularly challenging for directional drilling and requires specialized planning to execute well construction. Since the term was coined, the scope of [TERM] has broadened and the definition, which is now more flexible, includes deep wells with horizontal distance-to-depth, or H:V, ratios less than two. The drilling industry’s [TERM] database classifies wells, with increasing degree of well construction complexity, into low-, medium-, extended- and very extended-reach wells. Construction complexity depends on many factors, including water depth (for offshore wells), rig capability, geologic constraints and overall TVD. For example, a vertical well with TVD greater than 7,620 m [25,000 ft] is considered an extended-reach well. Also, depending on the conditions, drilling a well in deep water or through salt may be classified as [TERM] even if the well’s horizontal extent is not more than twice its TVD.', accepted_answers = array['ERD', 'extended reach drilling', 'extended-reach drilling']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'ERD';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'ERD' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('extended reach drilling', 'extended-reach drilling'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('extended reach drilling', 'extended-reach drilling');
update public.questions set question = '1. (n.) [Drilling] Another term for [TERM], a full-sized length of casing placed at the bottom of the casing string that is usually left full of cement on the inside to ensure that good cement remains on the outside of the bottom of the casing. If cement were not left inside the casing in this manner, the risk of overdisplacing the cement (due to improper casing volume calculations, displacement mud volume measurements, or both) would be significantly higher. Hence, the well designer plans on a safety margin of cement left inside the casing to guarantee that the fluid left outside the casing is good-quality cement. A float collar is placed at the top of the [TERM] and a float shoe placed at the bottom to prevent reverse flow of cement back into the casing after placement. There can be one, two or three joints of casing used for this purpose. | 2. (n.) [Well Completions] Another term for [TERM], a full-sized length of casing placed at the bottom of the casing string that is usually left full of cement on the inside to ensure that good cement remains on the outside of the bottom of the casing. If cement were not left inside the casing in this manner, the risk of overdisplacing the cement (due to improper casing volume calculations, displacement mud volume measurements, or both) would be significantly higher. Hence, the well designer plans on a safety margin of cement left inside the casing to guarantee that the fluid left outside the casing is good-quality cement. A float collar is placed at the top of the [TERM] and a float shoe placed at the bottom to prevent reverse flow of cement back into the casing after placement. There can be one, two or three joints of casing used for this purpose.', accepted_answers = array['float joint', 'shoe joint', 'shoe track']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'shoe joint';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'shoe joint' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('float joint', 'shoe track'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('float joint', 'shoe track');
update public.questions set question = '1. (n.) [Drilling] The large-diameter metal pipe that connects the bell nipple under the rotary table to the possum belly at the mud tanks. The [TERM] is simply an inclined, gravity-flow conduit to direct mud coming out the top of the wellbore to the mud surface-treating equipment. When drilling certain highly reactive clays, called "gumbo," the [TERM] may become plugged and require considerable effort by the rig crew to keep it open and flowing. In addition, the [TERM] is usually fitted with a crude paddle-type flow-measuring device commonly called a "flow show" that may give the driller the first indication that the well is flowing. | 2. (n.) [Production Testing] A surface pipeline carrying oil, gas or water that connects the wellhead to a manifold or to production facilities, such as heater-treaters and separators.', accepted_answers = array['flow line', 'flowline']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowline';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowline' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow line'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow line');
update public.questions set question = '[Drilling, Shale Gas] Abbreviation for logging while drilling. The measurement of formation properties during the excavation of the hole, or shortly thereafter, through the use of tools integrated into the bottomhole assembly. [TERM], while sometimes risky and expensive, has the advantage of measuring properties of a formation before drilling fluids invade deeply. Further, many wellbores prove to be difficult or even impossible to measure with conventional wireline tools, especially highly deviated wells. In these situations, the [TERM] measurement ensures that some measurement of the subsurface is captured in the event that wireline operations are not possible. Timely [TERM] data can also be used to guide well placement so that the wellbore remains within the zone of interest or in the most productive portion of a reservoir, such as in highly variable shale reservoirs.', accepted_answers = array['formation evaluation while drilling', 'logging-while-drilling', 'LWD']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'LWD';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'LWD' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('formation evaluation while drilling', 'logging-while-drilling'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('formation evaluation while drilling', 'logging-while-drilling');
update public.questions set question = '1. (n.) [Drilling] An inverted "U" shaped section of rigid piping normally used as a conduit for high-pressure drilling fluid. In particular, the term is applied to a structure that connects the top of a vertical standpipe running up the side of a derrick or mast to a flexible kelly hose that in turn is connected to another [TERM] between the flexible line and the swivel. | 2. (n.) [Well Workover and Intervention] The assembly mounted on a coiled tubing injector head that guides the tubing string as it passes through an arc from the reel into a vertical alignment with the injector-head chains and wellbore. The radius of the guide arch is generally designed to be as large as practicable since the plastic deformation created in the coiled tubing string induces material fatigue in the tube.', accepted_answers = array['goose neck', 'gooseneck']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'gooseneck';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'gooseneck' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('goose neck'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('goose neck');
update public.questions set question = '[Drilling] Another term for [TERM], an adapter that serves to connect the rotary table to the kelly. The [TERM] has an inside diameter profile that matches that of the kelly, usually square or hexagonal. It is connected to the rotary table by four large steel pins that fit into mating holes in the rotary table. The rotary motion from the rotary table is transmitted to the bushing through the pins, and then to the kelly itself through the square or hexagonal flat surfaces between the kelly and the [TERM]. The kelly then turns the entire drillstring because it is screwed into the top of the drillstring itself. Depth measurements are commonly referenced to the KB, such as 8327 ft KB, meaning 8327 feet below the [TERM].', accepted_answers = array['kelly bushing', 'rotary bushing']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'kelly bushing';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'kelly bushing' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('rotary bushing'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('rotary bushing');
update public.questions set question = '[Drilling] The magnitude of pressure exerted on a formation that causes fluid to be forced into the formation. The fluid may be flowing into the pore spaces of the rock or into cracks opened and propagated into the formation by the fluid pressure. This term is normally associated with a test to determine the strength of the rock, commonly called a pressure integrity test (PIT) or a [TERM] test (LOT). During the test, a real-time plot of injected fluid versus fluid pressure is plotted. The initial stable portion of this plot for most wellbores is a straight line, within the limits of the measurements. The [TERM] is the point of permanent deflection from that straight portion. The well designer must then either adjust plans for the well to this [TERM] pressure, or if the design is sufficiently conservative, proceed as planned.', accepted_answers = array['leak off', 'leakoff']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'leakoff';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'leakoff' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('leak off'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('leak off');
update public.questions set question = '[Drilling] Also known as [TERM] or [TERM], a test to determine the strength or fracture pressure of the open formation, usually conducted immediately after drilling below a new casing shoe. During the test, the well is shut in and fluid is pumped into the wellbore to gradually increase the pressure that the formation experiences. At some pressure, fluid will enter the formation, or leak off, either moving through permeable paths in the rock or by creating a space by fracturing the rock. The results of the [TERM] dictate the maximum pressure or mud weight that may be applied to the well during drilling operations. To maintain a small safety factor to permit safe well control operations, the maximum operating pressure is usually slightly below the [TERM] result.', accepted_answers = array['leakoff test', 'LOT', 'PIT', 'pressure integrity test']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'LOT';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'LOT' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('leakoff test', 'PIT', 'pressure integrity test'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('leakoff test', 'PIT', 'pressure integrity test');
update public.questions set question = '1. (n.) [Drilling] The reduced or total absence of fluid flow up the annulus when fluid is pumped through the drillstring. Though the definitions of different operators vary, this reduction of flow may generally be classified as seepage (less than 20 bbl/hr [3 m3/hr]), partial [TERM] (greater than 20 bbl/hr [3 m3/hr] but still some returns), and total [TERM] (where no fluid comes out of the annulus). In this severe latter case, the hole may not remain full of fluid even if the pumps are turned off. If the hole does not remain full of fluid, the vertical height of the fluid column is reduced and the pressure exerted on the open formations is reduced. This in turn can result in another zone flowing into the wellbore, while the loss zone is taking mud, or even a catastrophic loss of well control. Even in the two less severe forms, the loss of fluid to the formation represents a financial loss that must be dealt with, and the impact of which is directly tied to the per barrel cost of the drilling fluid and the loss rate over time. | 2. (n.) [Drilling Fluids] Another term for [TERM], a lack of mud returning to the surface after being pumped down a well. [TERM] occurs when the drill bit encounters natural fissures, fractures or caverns, and mud flows into the newly available space. [TERM] may also be caused by applying more mud pressure (that is, drilling overbalanced) on the formation than it is strong enough to withstand, thereby opening up a fracture into which mud flows.', accepted_answers = array['lost circulation', 'lost returns']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'lost returns';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'lost returns' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('lost circulation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('lost circulation');
update public.questions set question = '[Drilling] An adaptive drilling method used to precisely control the annular pressure throughout a wellbore. After determining the downhole pressure environment, drillers manage wellbore pressure constrained by the limits of formation properties. The annular pressure is kept slightly above the pore pressure to prevent the influx of formation fluids into the wellbore, but it is maintained well below the fracture initiation pressure. Rapid corrective actions can often be implemented in order to deal with observed pressure variations. The [TERM] process may utilize a variety of techniques including control of back pressure, adjusting mud density, modifying fluid rheology, adjusting the annular fluid level, controlling circulating friction and incorporating hole geometry in the well construction. The use of [TERM] to control the risks and costs of drilling wells that have narrow downhole pressure limits by actively managing the wellbore pressure profile has become a common practice. The dynamic control of annular pressures enables drilling wells that might not otherwise be practical.', accepted_answers = array['managed pressure drilling', 'MPD']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'MPD';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'MPD' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('managed pressure drilling'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('managed pressure drilling');
update public.questions set question = '[Drilling] A measure of drilling efficiency. [TERM] ([TERM]) is the energy required to remove a unit volume of rock. For optimal drilling efficiency, the objective is to minimize the [TERM] and to maximize the rate of penetration (ROP). To control the [TERM], drillers can control the weight on bit (WOB), torque, ROP, and drillbit revolutions per minute (rpm). Reference: Teale R: "The Concept of Specific Energy in Rock Drilling," International Journal of Rock Mechanics and Mining Sciences & Geomechanics Abstracts 2, no. 1 (March 1965): 57–73.', accepted_answers = array['mechanical specific energy', 'MSE']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'MSE';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'MSE' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('mechanical specific energy'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('mechanical specific energy');
update public.questions set question = '[Drilling] Term describing the uncased portion of a well. All wells, at least when first drilled, have [TERM] sections that the well planner must contend with. Prior to running casing, the well planner must consider how the drilled rock will react to drilling fluids, pressures and mechanical actions over time. The strength of the formation must also be considered. A weak formation is likely to fracture, causing a loss of drilling mud to the formation and, in extreme cases, a loss of hydrostatic head and potential well control problems. An extremely high-pressure formation, even if not flowing, may have wellbore stability problems. Once problems become difficult to manage, casing must be set and cemented in place to isolate the formation from the rest of the wellbore. While most completions are cased, some are open, especially in horizontal or extended-reach wells where it may not be possible to cement casing efficiently.', accepted_answers = array['open hole', 'openhole']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'openhole';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'openhole' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('open hole'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('open hole');
update public.questions set question = '[Drilling] Slang for penetration rate, or the speed that the bit is drilling into the formation.', accepted_answers = array['p rate', 'p-rate']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'p rate';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'p rate' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('p-rate'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('p-rate');
update public.questions set question = '1. (vb.) [Drilling] To plug the wellbore around a drillstring. This can happen for a variety of reasons, the most common being that either the drilling fluid is not properly transporting cuttings and cavings out of the annulus or portions of the wellbore wall collapse around the drillstring. When the well packs off, there is a sudden reduction or loss of the ability to circulate, and high pump pressures follow. If prompt remedial action is not successful, an expensive episode of stuck pipe can result. The term is also used in gravel packing to describe the act of placing all the sand or gravel in the annulus. | 2. (vb.) [Well Completions] To effect hydraulic isolation, either with a sealing device, such as a packer, or with a specialized plastic or fluid, such as a sealing compound.', accepted_answers = array['pack off', 'packoff']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'packoff';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'packoff' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('pack off'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('pack off');
update public.questions set question = '[Drilling] Abbreviation for [TERM], a downhole motor used in the oil field to drive the drill bit or other downhole tools during directional drilling or performance drilling applications. As drilling fluid is pumped through the [TERM], it converts the hydraulic power of the fluid into mechanical power to cause the bit to rotate. During directional drilling, this capability is used while drilling in sliding mode, when the drillstring is not rotated from the surface. [TERM] can also be used for performance drilling, straight hole drilling, coring, underreaming, and milling operations. In straight hole drilling, the motor functions as a drilling performance tool to increase the rate of penetration and reduce casing wear by minimizing drillstring rotation.', accepted_answers = array['PDM', 'positive displacement motor']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'PDM';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'PDM' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('positive displacement motor'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('positive displacement motor');
update public.questions set question = '[Drilling] Abbreviation for [TERM]. To remove the drillstring from the wellbore.', accepted_answers = array['POOH', 'pull out of the hole']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'POOH';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'POOH' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('pull out of the hole'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('pull out of the hole');
update public.questions set question = '[Drilling] Abbreviation for [TERM], a pressure-control device used during drilling for the purpose of making a seal around the drillstring while the drillstring rotates. The [TERM] is intended to contain hydrocarbons or other wellbore fluids and prevent their release to the atmosphere.', accepted_answers = array['RCD', 'rotating control device']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'RCD';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'RCD' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('rotating control device'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('rotating control device');
update public.questions set question = '[Drilling] Another term for [TERM], a drilling mud filled open steel or earthen berm tank that is not stirred or circulated. By having mud slowly pass through such a container, most large drilling solids sink to the bottom, cleaning the mud somewhat. If the [TERM] is small, as in the case of steel mud tanks, it must be cleaned out frequently as cuttings pile up on the bottom of the tank. In the early days of rotary drilling, some rigs had no more solids control than a large [TERM] into which mud was discharged after coming back from the wellbore and suction for the mud pumps was taken at the other end of the pit. A major drawback to this type of "cleaning" is that solids intentionally put into the mud, such as barite, may settle to the bottom and be discarded rather than circulated back into the wellbore.', accepted_answers = array['settling pit', 'settling tank']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'settling pit';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'settling pit' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('settling tank'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('settling tank');
update public.questions set question = '1. (n.) [Drilling] Also known as [TERM], a telescoping joint at the surface in floating offshore operations that permits vessel heave (vertical motion) while maintaining a riser pipe to the seafloor. As the vessel heaves, the [TERM] telescopes in or out by the same amount so that the riser below the [TERM] is relatively unaffected by vessel motion. | 2. (n.) [Well Completions] Also known as [TERM], a completion component designed to accommodate tubing movement or length changes while maintaining a hydraulic seal between the production conduit and the annulus. The size or length of the [TERM] depends on the wellbore conditions and completion characteristics.', accepted_answers = array['slip joint', 'travel joint']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'slip joint';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'slip joint' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('travel joint'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('travel joint');
update public.questions set question = '[Drilling] Another term for [TERM], a large-diameter, relatively low-pressure pipe string set in shallow yet competent formations for several reasons. First, the [TERM] protects fresh-water aquifers onshore. Second, the [TERM] provides minimal pressure integrity, and thus enables a diverter or perhaps even a blowout preventer (BOP) to be attached to the top of the [TERM] string after it is successfully cemented in place. Third, the [TERM] provides structural strength so that the remaining casing strings may be suspended at the top and inside of the [TERM].', accepted_answers = array['surface casing', 'surface pipe']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'surface pipe';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'surface pipe' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('surface casing'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('surface casing');
update public.questions set question = '[Drilling] To part or break the drillstring downhole due to either fatigue or excessive torque.', accepted_answers = array['twist off', 'twist-off']::text[] where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'twist off';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer = 'twist off' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('twist-off'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling' and source = 'SLB Glossary' and retired_at is null) and answer in ('twist-off');

-- Drilling Fluids
update public.questions set question = '1. (n.) [Drilling Fluids] The viscosity of a fluid measured at a given shear rate at a fixed temperature. In order for a viscosity measurement to be meaningful, the shear rate must be stated or defined. | 2. (n.) [Drilling Fluids] The viscosity of a fluid measured at the shear rate specified by API. In the Bingham plastic rheology model, [TERM] ([TERM]) is one-half of the dial reading at 600 rpm (1,022 sec–1 shear rate) using a direct-indicating, rotational viscometer. For example, a 600-rpm dial reading is 50 and the [TERM] is 50/2, or 25 cP.', accepted_answers = array['apparent viscosity', 'AV']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'AV';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'AV' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('apparent viscosity'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('apparent viscosity');
update public.questions set question = '[Drilling Fluids] Describing the amount (in percent) of a material added to cement when the material is added based on the total amount of a specific blend, often abbreviated as [TERM].', accepted_answers = array['BWOB', 'by weight of blend']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'BWOB';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'BWOB' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('by weight of blend'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('by weight of blend');
update public.questions set question = '[Drilling Fluids] Describing the amount (in percent) of a material added to cement, and is often abbreviated as [TERM]. [TERM] is the method used to describe the amount of most additives in the dry form.', accepted_answers = array['BWOC', 'by weight of cement']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'BWOC';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'BWOC' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('by weight of cement'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('by weight of cement');
update public.questions set question = '[Drilling Fluids] Describing the amount (in percent) of a material added to a cement slurry based on the weight of water used to mix the slurry. Commonly abbreviated as [TERM], this convention normally is used only for salt [NaCl].', accepted_answers = array['BWOW', 'by weight of water']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'BWOW';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'BWOW' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('by weight of water'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('by weight of water');
update public.questions set question = '[Drilling Fluids] The ability of a circulating drilling fluid to transport rock fragments out of a wellbore. [TERM] is an essential function of a drilling fluid, synonymous with hole-cleaning capacity and [TERM]. [TERM] is determined principally by the annular velocity, hole angle and flow profile of the drilling fluid, but is also affected by mud weight, cuttings size and pipe position and movement.', accepted_answers = array['carrying capacity', 'cuttings lifting', 'hole cleaning']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'hole cleaning';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'hole cleaning' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('carrying capacity', 'cuttings lifting'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('carrying capacity', 'cuttings lifting');
update public.questions set question = '1. (n.) [Drilling Fluids] A chemical whose molecular structure can envelop and hold a certain type of ion in a stable and soluble complex. Divalent cations, such as hardness ions, form stable and soluble complex structures with several types of sequestering chemicals. When held inside the complex, the ions have a limited ability to react with other ions, clays or polymers. Ethylenediamine tetraacetic acid (EDTA) is a well-known [TERM] for the hardness ions, such as Ca+2, and is the reagent solution used in the hardness test protocol published by API. Polyphosphates can also sequester hardness ions. The addition of sodium acid pyrophosphate (SAPP) to a cement-contaminated mud renders the calcium ions essentially nonreactive with clays in the mud. As a side benefit, SAPP also lowers mud pH. Sequestering is not the same as precipitation because sequestering does not form a solid. | 2. (n.) [Well Completions, Drilling Fluids, Well Workover and Intervention] Another term for [TERM], a chemical used to bind metal ions to form a ring structure. [TERM] stabilize or prevent the precipitation of damaging compounds. In the oil field, [TERM] are used in stimulation treatments and for cleaning surface facilities. They are also used to treat or remove scale or weighting agents in reservoir drilling fluids. During acid or scale-removal treatments, various compounds may be dissolved in the treatment fluid. As the acid reacts and the pH increases, reaction products may precipitate as a gelatinous, insoluble mass. Should this occur within the formation matrix, it is almost impossible to remove and permanent permeability damage may occur. [TERM] prevent precipitation by keeping ions in a soluble form until the treatment fluid can be flowed back from the formation during cleanup. Typical oilfield [TERM] include EDTA (ethylenediamine tetraacetic acid), HEDTA (hydroxyethylenediamine triacetic acid), NTA (nitriolotriacetic acid) and citric acid. | 3. (n.) [Enhanced Oil Recovery] Another term for [TERM], a chemical added to an acid to stabilize iron. The injected acid dissolves iron from rust, millscale, iron scales or iron-containing minerals in the formation. Iron can exist as ferric iron [Fe+3] or ferrous iron [Fe+2]. If the iron is not controlled, it will precipitate insoluble products such as ferric hydroxide and, in sour environments, ferrous sulfide [FeS], which will damage the formation. [TERM] associate with iron [Fe+3 or Fe+2] to form soluble complexes. Citric acid, acetic acid and EDTA are effective [TERM] and can be used at temperatures up to 400oF [204oC].', accepted_answers = array['chelating agent', 'sequestering agent']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'chelating agent';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'chelating agent' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sequestering agent'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sequestering agent');
update public.questions set question = '[Drilling Fluids] Another term for [TERM], a slurry that consists of bentonite, cement or polymers mixed into an oil; bentonite in diesel oil is commonly used as a [TERM]. A small batch of the slurry is pumped down a well that has lost circulation to seal the leaky zone. The [TERM] may or may not be squeezed by pressure into the zone. Water downhole interacts with the bentonite, cement or polymers to make a sticky gunk.', accepted_answers = array['diesel-oil plug', 'gunk plug']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'gunk plug';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'gunk plug' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('diesel-oil plug'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('diesel-oil plug');
update public.questions set question = '1. (n.) [Drilling] Also known as [TERM], a condition whereby the drillstring cannot be moved (rotated or reciprocated) along the axis of the wellbore. [TERM] typically occurs when high-contact forces caused by low reservoir pressures, high wellbore pressures, or both, are exerted over a sufficiently large area of the drillstring. [TERM] is, for most drilling organizations, the greatest drilling problem worldwide in terms of time and financial cost. It is important to note that the sticking force is a product of the differential pressure between the wellbore and the reservoir and the area that the differential pressure is acting upon. This means that a relatively low differential pressure (delta p) applied over a large working area can be just as effective in sticking the pipe as can a high differential pressure applied over a small area. | 2. (n.) [Drilling Fluids] A situation in which the drilling assembly (pipe, drill collars and bottomhole assembly) is stuck in filter cake that was previously deposited on a permeable zone. The pipe is held in the cake by a difference in pressures between the hydrostatic pressure of the mud and the pore pressure in the permeable zone. The force required to pull the pipe free can exceed the strength of the pipe. Methods used to get the pipe free, in addition to pulling and torquing the pipe, include: (1) lowering hydrostatic pressure in the wellbore, (2) placing a spotting fluid next to the stuck zone and (3) applying shock force just above the stuck point by mechanical jarring, or (4) all the above. The most common approach, however, to getting free is to place a spot of oil, oil-base mud, or special spotting fluid.', accepted_answers = array['differential sticking', 'wall sticking']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'wall sticking';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'wall sticking' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('differential sticking'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('differential sticking');
update public.questions set question = '[Drilling Fluids] Pertaining to cement that is highly sensitive to the concentration of dispersant, often leading to slurry-stability problems. The term is commonly abbreviated ETD. Antonyms: [TERM]', accepted_answers = array['difficult to disperse', 'easy to disperse']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'easy to disperse';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'easy to disperse' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('difficult to disperse'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('difficult to disperse');
update public.questions set question = '[Drilling Fluids] Also called [TERM], which is water added to maintain or dilute a water-mud system. The added water may be fresh water, seawater or salt water, as appropriate for the mud. [TERM] volume is an important parameter in a material balance check on solids content and solids removal efficiency for a mud system. The amount of dilution strongly influences mud economics. If soft [TERM] is needed, treatments to remove hardness ions should be done prior to adding the water to the mud to avoid clay flocculation and polymer precipitation.', accepted_answers = array['dilution water', 'make-up water']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'make-up water';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'make-up water' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('dilution water'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('dilution water');
update public.questions set question = '[Drilling Fluids] Also known as [TERM] or V-G meter, an instrument used to measure viscosity and gel strength of drilling mud. The [TERM] is a rotational cylinder and bob instrument. Two speeds of rotation, 300 and 600 rpm, are available in all instruments, but some are 6- or variable-speed. It is called "direct-indicating" because, at a given speed, the dial reading is a true centipoise viscosity. For example, at 300 rpm, the dial reading (511 sec–1) is a true viscosity. Bingham plastic rheological parameters are easily calculated from [TERM] readings: PV (in units of cP) = 600 dial - 300 dial and YP (in units of lbm/100 ft2) = 300 dial - PV. Gel strength is also directly read as dial readings in oilfield units of lbm/100 ft2.', accepted_answers = array['direct-indicating viscometer', 'Fann viscometer']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'Fann viscometer';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'Fann viscometer' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('direct-indicating viscometer'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('direct-indicating viscometer');
update public.questions set question = '[[TERM]] Any of a number of liquid and gaseous fluids and mixtures of fluids and solids (as solid suspensions, mixtures and emulsions of liquids, gases and solids) used in operations to drill boreholes into the earth. Synonymous with "[TERM]" in general usage, although some prefer to reserve the term "[TERM]" for more sophisticated and well-defined "[TERM]." Classifications of [TERM] has been attempted in many ways, often producing more confusion than insight. One classification scheme, given here, is based only on the [TERM] composition by singling out the component that clearly defines the function and performance of the fluid: water based nonaqueous based gaseous (pneumatic). Each category has a variety of subcategories that overlap each other considerably. For more details, see The Defining Series: [TERM] Basics.', accepted_answers = array['drilling fluid', 'drilling mud', 'mud']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('drilling fluid', 'drilling mud'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('drilling fluid', 'drilling mud');
update public.questions set question = '[Drilling Fluids] Ethylenediamine tetraacetic acid, the reagent used to titrate for calcium and magnesium ions (hardness ions) in water samples. It is also known as [TERM] or titraver.', accepted_answers = array['EDTA', 'versenate']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'EDTA';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'EDTA' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('versenate'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('versenate');
update public.questions set question = '[Drilling Fluids] During a titration procedure in analytical chemistry, the point at which reagent addition should be immediately stopped and the volume of reagent recorded. The [TERM] represents the end of a specific chemical reaction, such as precipitation, and may be indicated by a color change, a voltage or pH reading or an inflection point on a graphical plot of the data.', accepted_answers = array['end point', 'endpoint']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'endpoint';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'endpoint' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('end point'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('end point');
update public.questions set question = '[Drilling Fluids] Also known as [TERM], a cationic amine salt in which the nitrogen atom has four groups bonded to it and carries a positive charge. [TERM] are used as oil-wetting agents, corrosion and shale inhibitors and bactericides.', accepted_answers = array['film-forming amine', 'quat amine', 'quaternary amine']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'quat amine';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'quat amine' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('film-forming amine', 'quaternary amine'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('film-forming amine', 'quaternary amine');
update public.questions set question = '[Drilling Fluids] The residue deposited on a permeable medium when a slurry, such as a drilling fluid, is forced against the medium under a pressure. Filtrate is the liquid that passes through the medium, leaving the cake on the medium. Drilling muds are tested to determine filtration rate and filter-cake properties. Cake properties such as cake thickness, toughness, slickness and permeability are important because the cake that forms on permeable zones in the wellbore can cause stuck pipe and other drilling problems. Reduced oil and gas production can result from reservoir damage when a poor [TERM] allows deep filtrate invasion. A certain degree of cake buildup is desirable to isolate formations from drilling fluids. In openhole completions in high-angle or horizontal holes, the formation of an external [TERM] is preferable to a cake that forms partly inside the formation. The latter has a higher potential for formation damage.', accepted_answers = array['filter cake', 'filtercake']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'filtercake';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'filtercake' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('filter cake'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('filter cake');
update public.questions set question = '[Drilling Fluids] Another term for [TERM] in a fluid. [TERM] opposes the movement of mud, whether by pumping or movement of pipe in a wellbore. Excessive [TERM] can develop after a mud has been quiescent in the hole at high temperature for a period of time. [TERM] can be measured according to procedures published by the API.', accepted_answers = array['gel strength', 'shear strength']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'gel strength';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'gel strength' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('shear strength'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('shear strength');
update public.questions set question = '[Drilling Fluids, Geology] Also known as [TERM], the rate of increase in temperature per unit depth in the Earth. Although the [TERM] varies from place to place, it averages 25 to 30 °C/km [15 °F/1000 ft]. [TERM] sometimes increase dramatically around volcanic areas. It is particularly important for drilling fluids engineers to know the [TERM] in an area when they are designing a deep well. The downhole temperature can be calculated by adding the surface temperature to the product of the depth and the [TERM].', accepted_answers = array['geothermal gradient', 'temperature gradient', 'thermal gradient']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'thermal gradient';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'thermal gradient' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('geothermal gradient', 'temperature gradient'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('geothermal gradient', 'temperature gradient');
update public.questions set question = '[Drilling Fluids] Also known as [TERM], a high-specific gravity and finely divided solid material used to increase density of a drilling fluid. (Dissolved salts that increase fluid density, such as calcium bromide in brines, are not called [TERM].) Barite is the most common, with minimum specific gravity of 4.20 g/cm3. Hematite is a more dense material, with minimum specific gravity of 5.05 g/cm3, per API and ISO specifications. Calcium carbonate, specific gravity 2.7 to 2.8, is considered [TERM] but is used more for its acid solubility than for density. Siderite, specific gravity around 3.8, has been used to densify mud, but can cause problems by dissolving into the mud at high pH. Ilmenite, specific gravity of 4.6 has been used in drilling fluid and cement. Only barite and hematite have API/ISO standards.', accepted_answers = array['HGS', 'high-gravity solids', 'high-specific-gravity solids', 'weight material', 'weighting agent', 'weighting material']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'HGS';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'HGS' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('high-gravity solids', 'high-specific-gravity solids', 'weight material', 'weighting agent', 'weighting material'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('high-gravity solids', 'high-specific-gravity solids', 'weight material', 'weighting agent', 'weighting material');
update public.questions set question = '[Drilling, Drilling Fluids, Production Facilities, Well Testing, Well Workover and Intervention, Well Completions] [H2S] An extraordinarily poisonous gas with a molecular formula of H2S. At low concentrations, H2S has the odor of rotten eggs, but at higher, lethal concentrations, it is odorless. H2S is hazardous to workers and a few seconds of exposure at relatively low concentrations can be lethal, but exposure to lower concentrations can also be harmful. The effect of H2S depends on duration, frequency and intensity of exposure as well as the susceptibility of the individual. [TERM] is a serious and potentially lethal hazard, so awareness, detection and monitoring of H2S is essential. Since [TERM] gas is present in some subsurface formations, drilling and other operational crews must be prepared to use detection equipment, personal protective equipment, proper training and contingency procedures in H2S-prone areas. [TERM] is produced during the decomposition of organic matter and occurs with hydrocarbons in some areas. It enters drilling mud from subsurface formations and can also be generated by sulfate-reducing bacteria in stored muds. H2S can cause sulfide-stress-corrosion cracking of metals. Because it is corrosive, H2S production may require costly special production equipment such as stainless steel tubing. Sulfides can be precipitated harmlessly from water muds or oil muds by treatments with the proper sulfide scavenger. H2S is a weak acid, donating two hydrogen ions in neutralization reactions, forming HS- and S-2 ions. In water or water-base muds, the three sulfide species, H2S and HS- and S-2 ions, are in dynamic equilibrium with water and H+ and OH- ions. The percent distribution among the three sulfide species depends on pH. H2S is dominant at low pH, the HS- ion is dominant at mid-range pH and S2 ions dominate at high pH. In this equilibrium situation, sulfide ions revert to H2S if pH falls. Sulfides in water mud and oil mud can be quantitatively measured with the Garrett Gas Train according to procedures set by API.', accepted_answers = array['hydrogen sulfide', 'sulfide stress cracking']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'hydrogen sulfide';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'hydrogen sulfide' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sulfide stress cracking'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sulfide stress cracking');
update public.questions set question = '[Drilling Fluids] Also known as [TERM] or [TERM], a synthetic hydrocarbon liquid made by the polymerization of ethylene, H2C=CH2. [TERM] are one of several synthetic fluids that have recently been used as base for synthetic-base muds and in other applications where refined oils might otherwise be used except for HSE concerns. [TERM] are linear structures that have their olefin double bond in the center of the chain length. They are made by isomerization of linear alphaolefins (LAO), which have their double bond at the end of the chain. Because the olefin bond is in the central area of the chain, the physical properties of [TERM] are different (for example, they are generally lower viscosity) compared with the LAOs from which they are made.', accepted_answers = array['IO', 'isomerized olefin', 'polyolefin']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'IO';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'IO' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('isomerized olefin', 'polyolefin'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('isomerized olefin', 'polyolefin');
update public.questions set question = '[Drilling Fluids] Abbreviation for the International Organization for Standardization, a developer and publisher of international standards. [TERM] is a network of national-standards institutes from 157 countries, with one member per country and a Central Secretariat that coordinates the system from offices in Geneva, Switzerland. (Recognizing that the acronym for International Organization for Standardization would vary widely from one member country to the next, [TERM] founders decided to standardize the organization acronym. [TERM] is derived from the Greek [TERM], meaning equal.) API and [TERM] joint committees are developing standards for worldwide use.', accepted_answers = array['ISO', 'octyl alcohol']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'ISO';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'ISO' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('octyl alcohol'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('octyl alcohol');
update public.questions set question = '1. (n.) [Drilling Fluids] Abbreviation for the US oilfield unit of concentration, [TERM], more correctly written as [TERM]. One [TERM] is the equivalent of one pound of additive in 42 US gallons of mud. The "m" is used to denote mass to avoid possible confusion with pounds force (denoted by "lbf"). In SI units, the conversion factor is one pound per barrel equals 2.85 kilograms per cubic meter. For example, 10 [TERM] = 28.5 kg/m3. | 2. (n.) [Drilling Fluids] Abbreviation for concentration, parts-per-billion. For example, lead in a water sample may be 10 [TERM].', accepted_answers = array['lbm/bbl', 'parts per billion', 'pounds per barrel', 'ppb']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'ppb';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'ppb' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('lbm/bbl', 'parts per billion', 'pounds per barrel'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('lbm/bbl', 'parts per billion', 'pounds per barrel');
update public.questions set question = '1. (n.) [Drilling] The reduced or total absence of fluid flow up the annulus when fluid is pumped through the drillstring. Though the definitions of different operators vary, this reduction of flow may generally be classified as seepage (less than 20 bbl/hr [3 m3/hr]), partial [TERM] (greater than 20 bbl/hr [3 m3/hr] but still some returns), and total [TERM] (where no fluid comes out of the annulus). In this severe latter case, the hole may not remain full of fluid even if the pumps are turned off. If the hole does not remain full of fluid, the vertical height of the fluid column is reduced and the pressure exerted on the open formations is reduced. This in turn can result in another zone flowing into the wellbore, while the loss zone is taking mud, or even a catastrophic loss of well control. Even in the two less severe forms, the loss of fluid to the formation represents a financial loss that must be dealt with, and the impact of which is directly tied to the per barrel cost of the drilling fluid and the loss rate over time. | 2. (n.) [Drilling Fluids] Another term for [TERM], a lack of mud returning to the surface after being pumped down a well. [TERM] occurs when the drill bit encounters natural fissures, fractures or caverns, and mud flows into the newly available space. [TERM] may also be caused by applying more mud pressure (that is, drilling overbalanced) on the formation than it is strong enough to withstand, thereby opening up a fracture into which mud flows.', accepted_answers = array['lost circulation', 'lost returns']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'lost returns';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'lost returns' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('lost circulation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('lost circulation');
update public.questions set question = '[Drilling Fluids] An oil mud designed and maintained with a minimum of colloid-sized solids, typically by omitting fatty-acid soap and lime, and minimizing organophilic clays and fluid-loss additives. [TERM], also called a relaxed filtrate oil mud, increases drilling rate. A disadvantage is that filter cake formed on sands is not tight, can quickly become very thick, and can cause pipe to stick by differential pressure.', accepted_answers = array['low colloid oil mud', 'low-colloid oil mud']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'low colloid oil mud';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'low colloid oil mud' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('low-colloid oil mud'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('low-colloid oil mud');
update public.questions set question = '[Drilling Fluids] A type of drilling-fluid solid having a lower density than the barite or hematite that is used to weight up a drilling fluid, including drill solids plus the added bentonite clay. The mud engineer calculates the concentration of these and other types of solids on the basis of mud weight, retort analysis, chloride titrations and other information. Solids are reported as lbm/bbl or vol.%. Water is 1.0, barite 4.20, and hematite 5.505 g/cm3. [TERM] are normally assumed to have a density of 2.60 g/cm3.', accepted_answers = array['low gravity solids', 'low-gravity solids']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'low gravity solids';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'low gravity solids' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('low-gravity solids'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('low-gravity solids');
update public.questions set question = '[Drilling Fluids] Native clays that are generally unsuitable for use in a clay-based drilling mud. [TERM] are considered to be drill solids, although they may give high values for bentonite-equivalent in a mud according to the methylene blue test.', accepted_answers = array['low yield clay', 'low-yield clay']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'low yield clay';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'low yield clay' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('low-yield clay'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('low-yield clay');
update public.questions set question = '[Drilling Fluids] Mathematical relationship between the densities and the corresponding volumes of mixtures of liquid-solid slurries and clear fluid blends, such as drilling muds and completion fluids. Assumptions are: (1) masses and volumes of components are additive and (2) material is neither generated nor lost from the system. As a simple example, below are the two [TERM] for a three-component mixture of oil (o), water (w) and solids (s), where V = volume percent, D = specific density and MW = mixture weight. (This could represent a simple, weighted oil-base mud formulation.) MW = DsVs + DoVo + DwVw 100% = Vs + Vo + Vw. By solving these equations simultaneously, an unknown parameter can be found if other parameters are known or can be estimated accurately. [TERM] are used to derive formulations of muds, to calculate the amount of barite needed to weight-up a mud, to determine the amount of water needed to dilute a mud, and to find the volume of two or more muds to mix together to achieve a new mud weight and volume. Material balance is also the basis for calculating solids content of muds based on mud testing data.', accepted_answers = array['material balance equation', 'material-balance equation']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'material balance equation';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'material balance equation' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('material-balance equation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('material-balance equation');
update public.questions set question = '1. (n.) [Drilling Fluids] Abbreviation for [TERM], a branch of the US Lands and Mineral Management Department formerly charged with supervising national resources. [TERM] had oversight of oil and gas leasing, royalty collection and other operations in US-owned areas. It was responsible for closely monitoring operations in federal waters, overseeing leasing of acreage, issuing drilling permits and monitoring operators for permit violations. From 2010 to 2011, the [TERM] was replaced by three independent agencies within the US Department of Interior: Office of Natural Resources Revenue (ONRR) for revenue collection Bureau of Ocean Energy Management (BOEM) for US offshore resources management Bureau of Safety and Environmental Enforcement (BSEE) for safety and environmental regulations enforcement. | 2. (n.) [Drilling Fluids] A product similar to mixed-metal hydroxide, but based on silicate chemistry', accepted_answers = array['Minerals Management Service', 'MMS']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'MMS';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'MMS' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('Minerals Management Service'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('Minerals Management Service');
update public.questions set question = '[Drilling Fluids] Another term for [TERM], a device to measure density (weight) of mud, cement or other liquid or slurry. A [TERM] consists of a fixed-volume mud cup with a lid on one end of a graduated beam and a counterweight on the other end. A slider-weight can be moved along the beam, and a bubble indicates when the beam is level. Density is read at the point where the slider-weight sits on the beam at level. Accuracy of mud weight should be within ± 0.1 lbm/galUS (± 0.01 g/cm3). A [TERM] can be calibrated with water or other liquid of known density by adjusting the counter weight. Most balances are not pressurized, but a pressurized [TERM] operates in the same manner.', accepted_answers = array['mud balance', 'mud scale']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud scale';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud scale' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('mud balance'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('mud balance');
update public.questions set question = '[Drilling Fluids] Another term for [TERM], a cylindrical vessel in which a mud sample can be heated under pressure. Cells, often called bombs, are routinely used for static-aging and hot-roll aging of mud samples. Cells are usually made of metal or metal alloy, such as stainless steel or aluminum bronze, and have open tops. Caps should be fitted with a valve so that gas pressure can be applied and then released before opening the cell. Common sizes are 260 and 500 cm3, to accommodate half- and one-barrel equivalent volumes, plus space for thermal expansion. Glass or plastic jars can be used judiciously when pressure is nil and temperature is limited to below about 150 degF [66 degC].', accepted_answers = array['mud cell', 'mud-aging cell']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud cell';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud cell' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('mud-aging cell'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('mud-aging cell');
update public.questions set question = '[Drilling Fluids] Referring to mud [TERM], the mass per unit volume of a drilling fluid, synonymous with [TERM]. [TERM] is reported in lbm/gal (also known as ppg), kg/m3 or g/cm3 (also called specific gravity or SG), lb/ft3 or in hydrostatic gradient, lb/in2/ft (psi/ft) or pptf (psi/1000 ft). Mud [TERM] controls hydrostatic pressure in a wellbore and prevents unwanted flow into the well. The [TERM] of the mud also prevents collapse of casing and the openhole. Excessive mud [TERM] can cause lost circulation by propagating, and then filling, fractures in the rock. Mud [TERM] (density) test procedures using a mud balance have been standardized and published by the API.', accepted_answers = array['mud density', 'mud weight', 'weight']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'weight';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'weight' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('mud density', 'mud weight'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('mud density', 'mud weight');
update public.questions set question = '[Drilling Fluids] The mud flowing into the well. The [TERM] is taken from the suction pit (the last pit in the flow series) just before the mud goes into the pump and down the wellbore. The in sample is also called the suction-pit sample, or "[TERM]" on a drilling fluid report. This mud has been treated and properly weighted and is in good condition to encounter downhole pressures, temperatures and contamination. Comparisons are made between properties of this [TERM] and the "out" or mud-out sample taken at surface prior to solids removal.', accepted_answers = array['mud in', 'mud-in sample']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud in';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud in' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('mud-in sample'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('mud-in sample');
update public.questions set question = '[Drilling Fluids] Abbreviation for the expression of concentration, [TERM]. For solid and liquid concentrations, [TERM] refers to weight (mass) units. For example: calcite in a ground barite sample may be 400 [TERM] calcium chloride in a water solution may be 250,000 [TERM]. The relationship of [TERM] to weight percentage is 10,000 [TERM] = 1 wt%. For gases, [TERM] refers to volume (or mole) units. For example, H2S in an air sample may be 10 [TERM] (both by volume and by moles).', accepted_answers = array['parts per million', 'ppm']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'ppm';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'ppm' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('parts per million'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('parts per million');
update public.questions set question = '[Drilling Fluids] A solvent used with water to break the emulsion of an oil-base or synthetic-base drilling fluid to prepare the sample for chemical titrations to determine lime, calcium or chloride content according to API testing procedures. [TERM] is an abbreviation for [TERM]. It is an environmentally friendlier replacement of a xylene-isopropynol mixture previously used in certain titrations.', accepted_answers = array['PNP', 'propylene glycol normal propyl ether']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'PNP';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'PNP' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('propylene glycol normal propyl ether'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('propylene glycol normal propyl ether');
update public.questions set question = '[Drilling Fluids] Also known as [TERM], the volume percent (or fraction) of a mud that is not captured in the receiver when performing the water, oil and solids test as prescribed by API. [TERM] thus include suspended solids, dissolved solids (salts), charred organic materials and volatile materials that do not condense. For calculations, [TERM] are normally assumed to be only suspended and dissolved solids. Volume percent suspended solids (weighting material plus drill solids) is of particular interest to mud engineers. To calculate that percentage, the volume increase caused by the dissolved salts is determined from filtrate analyses of chloride and calcium ions. For oil muds, the calculations are more complicated.', accepted_answers = array['retort solids', 'total solids']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'total solids';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'total solids' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('retort solids'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('retort solids');
update public.questions set question = '[Drilling Fluids] The characteristic of a cement slurry whose consistency changes from the point of departure or 30 Bc to 100 Bc in a short time. The term refers to the characteristic 90° bend in a plot of cement consistency versus time.', accepted_answers = array['right angle set', 'right-angle set']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'right angle set';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'right angle set' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('right-angle set'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('right-angle set');
update public.questions set question = '[Drilling Fluids] Abbreviation for [TERM], a sequestering agent used to treat cement contamination and a deflocculant for low-temperature water muds.', accepted_answers = array['SAPP', 'sodium acid pyrophosphate']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'SAPP';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'SAPP' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sodium acid pyrophosphate'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sodium acid pyrophosphate');
update public.questions set question = '[Drilling Fluids] Another term for [TERM], a chemical with the formula Na2CO3. It is called [TERM] at the drilling rig and is used to treat most types of calcium ion contamination in freshwater and seawater muds. For cement contamination, sodium bicarbonate is used. Calcium ions from drilling gypsum or anhydrite, CaSO4, cause clay flocculation and polymer precipitation and lower pH. A soda-ash treatment is appropriate for gypsum contamination because caustic soda, NaOH, is not needed to raise pH. This is also generally the case with hard water influxes into water muds.', accepted_answers = array['soda ash', 'sodium carbonate']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'soda ash';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'soda ash' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sodium carbonate'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sodium carbonate');
update public.questions set question = '[Drilling Fluids] Abbreviation for [TERM]. [TERM] is the result of neutralizing a linear, anionic polymer made from the monomer acrylic acid, CH2=CHCOO- H+, with sodium hydroxide (NaOH). Polyacrylates are best utilized in soft water with low salinity to achieve the best dispersion and full chain elongation. Even low concentrations of hardness ions, for example, Ca+2, precipitate polyacrylates. Low molecular-weight polyacrylates are used as clay deflocculants. High molecular weight polymers are used for fluid-loss control and as a clay extender. As an extender, [TERM] is added to bentonite at the grinding plant. It is also used at the rig in low-solids mud. Divalent cations can negate its benefits as a clay extender. [TERM] is highly efficient when used to flocculate colloids in native-solids muds, clear-water muds and wastewater cleanup. The polymer chain links together colloidal solids that can be removed by gravity settling in shallow pits or by applying hydrocyclone, centrifuge or filtration techniques.', accepted_answers = array['sodium polyacrylate', 'SPA']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'SPA';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'SPA' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sodium polyacrylate'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('sodium polyacrylate');
update public.questions set question = '[Drilling Fluids] A polysaccharide secreted by the bacteria genus Xanthomonas campestris, also known as [TERM]. XC in water muds provides non-Newtonian mud rheology, highly desirable because of the flat velocity profile it produces in annular flow, which is required for efficient cuttings lifting in lower density muds. [TERM] is anionic, with tolerance for salinity and fair tolerance for hardness ions. XC is a finely powdered material that can vary in the amount of residual bacteria debris and the ease with which it disperses into water. Temperature tolerance varies with water-phase components but starts to degrade around 200 to 250 degF [93 to 121 degC]. Extreme pH or hardness are not well-tolerated by [TERM] and it is susceptible to bacterial attack.', accepted_answers = array['xanthan gum', 'XC polymer']::text[] where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'XC polymer';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer = 'XC polymer' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('xanthan gum'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Drilling Fluids' and source = 'SLB Glossary' and retired_at is null) and answer in ('xanthan gum');

-- Enhanced Oil Recovery
update public.questions set question = '[Enhanced Oil Recovery] Abbreviation for a combination of forward combustion and waterflooding, also called [TERM] or in situ steam generation. [TERM] is an in situ combustion technique in which water is injected simultaneously or alternately with air into a formation. [TERM] actually refers to wet forward combustion and was developed to use the great amount of heat that would otherwise be lost in the formation. The injected water recovers the heat from behind the burning front and transfers it to the oil bank ahead. Because of this additional energy, the oil displacement is more efficient and requires less air. In spite of these advantages, a [TERM] process cannot avoid liquid-blocking problems and use of [TERM] is limited by the oil viscosity.', accepted_answers = array['COFCAW', 'wet combustion']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'COFCAW';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'COFCAW' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('wet combustion'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('wet combustion');
update public.questions set question = '[[TERM]] Abbreviation for [TERM], an oil recovery enhancement method using sophisticated techniques that alter the original properties of oil. Once ranked as a third stage of oil recovery that was carried out after secondary recovery, the techniques employed during [TERM] can actually be initiated at any time during the productive life of an oil reservoir. Its purpose is not only to restore formation pressure, but also to improve oil displacement or fluid flow in the reservoir. The three major types of [TERM] operations are chemical flooding (alkaline flooding or micellar-polymer flooding) miscible displacement (carbon dioxide [CO2] injection or hydrocarbon injection) thermal recovery (steamflood or in-situ combustion). The optimal application of each type depends on reservoir temperature, pressure, depth, net pay, permeability, residual oil and water saturations, porosity and fluid properties such as oil API gravity and viscosity. [TERM] is also known as [TERM] or [TERM].', accepted_answers = array['enhanced oil recovery', 'EOR', 'improved oil recovery', 'tertiary recovery']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'EOR';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'EOR' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('enhanced oil recovery', 'improved oil recovery', 'tertiary recovery'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('enhanced oil recovery', 'improved oil recovery', 'tertiary recovery');
update public.questions set question = '[Enhanced Oil Recovery] A type of corrosion produced when easily removed scales (such as iron carbonate) that were initially protecting the metals in the pipe are eroded and the underlying metals are corroded. [TERM] is a common cause of failure in oilfield equipment. The attack is normally localized at changes of pipe sections, bends or elbows where there is high velocity or turbulent flow.', accepted_answers = array['erosion corrosion', 'erosion-corrosion']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'erosion corrosion';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'erosion corrosion' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('erosion-corrosion'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('erosion-corrosion');
update public.questions set question = '[Enhanced Oil Recovery] Also known as [TERM], the particular arrangement of production and injection wells. The [TERM] for an individual field or part of a field is based on the location of existing wells, reservoir size and shape, cost of new wells and the recovery increase associated with various [TERM]. The flood pattern can be altered during the life of a field to change the direction of flow in a reservoir with the intent of contacting unswept oil. It is common to reduce the pattern size by infill drilling, which improves oil recovery by increasing reservoir continuity between injectors and producers. Common [TERM] are direct line drive, staggered line drive, two-spot, three-spot, four-spot, five-spot, seven-spot and nine-spot. Normally, the two-spot and three-spot patterns are used for pilot testing purposes. The patterns are called normal or regular when they include only one production well per pattern. Patterns are described as inverted when they include only one injection well per pattern.', accepted_answers = array['flooding pattern', 'injection pattern']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'flooding pattern';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'flooding pattern' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('injection pattern'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('injection pattern');
update public.questions set question = '[Enhanced Oil Recovery, Heavy Oil] A method of thermal recovery in which fire is generated inside the reservoir by injecting a gas containing oxygen, such as air. A special heater in the well ignites the oil in the reservoir and starts a fire. The heat generated by burning the heavy hydrocarbons in place produces hydrocarbon cracking, vaporization of light hydrocarbons and reservoir water in addition to the deposition of heavier hydrocarbons known as coke. As the fire moves, the burning front pushes ahead a mixture of hot combustion gases, steam and hot water, which in turn reduces oil viscosity and displaces oil toward production wells. Additionally, the light hydrocarbons and the steam move ahead of the burning front, condensing into liquids, which adds the advantages of miscible displacement and hot waterflooding. [TERM] is also known as fire flooding or fireflood.', accepted_answers = array['in situ combustion', 'in-situ combustion']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'in situ combustion';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'in situ combustion' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('in-situ combustion'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('in-situ combustion');
update public.questions set question = '[Enhanced Oil Recovery] Another term for [TERM], the minimum quantity of additional components, such as intermediate-chain gases or CO2, that must be added to an injection gas to reach first-contact miscibility with a reservoir fluid at a given temperature and pressure. At [TERM] conditions, the interfacial tension is zero and no interface exists between the fluids.', accepted_answers = array['minimum miscibility concentration', 'minimum miscibility enrichment']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'minimum miscibility enrichment';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'minimum miscibility enrichment' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('minimum miscibility concentration'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('minimum miscibility concentration');
update public.questions set question = '[Enhanced Oil Recovery, Production Testing] Also known as [TERM], the first stage of hydrocarbon production, in which natural reservoir energy, such as gasdrive, waterdrive or gravity drainage, displaces hydrocarbons from the reservoir, into the wellbore and up to surface. Initially, the reservoir pressure is considerably higher than the bottomhole pressure inside the wellbore. This high natural differential pressure drives hydrocarbons toward the well and up to surface. However, as the reservoir pressure declines because of production, so does the differential pressure. To reduce the bottomhole pressure or increase the differential pressure to increase hydrocarbon production, it is necessary to implement an artificial lift system, such as a rod pump, an electrical submersible pump or a gas-lift installation. Production using artificial lift is considered [TERM]. The [TERM] stage reaches its limit either when the reservoir pressure is so low that the production rates are not economical, or when the proportions of gas or water in the production stream are too high. During [TERM], only a small percentage of the initial hydrocarbons in place are produced, typically around 10% for oil reservoirs.', accepted_answers = array['primary production', 'primary recovery']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'primary recovery';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'primary recovery' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('primary production'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('primary production');
update public.questions set question = '[Enhanced Oil Recovery, Heavy Oil] Another term for [TERM], in cyclic steam injection, the second phase between the steam-injection phase and the production phase. During the [TERM], the well is shut in for several days to allow uniform heat distribution to thin the oil.', accepted_answers = array['soak phase', 'steam soak']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'soak phase';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'soak phase' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('steam soak'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('steam soak');
update public.questions set question = '[Heavy Oil, Enhanced Oil Recovery] Abbreviation for thermal enhanced oil recovery, also known as [TERM], a general term for injection processes that introduce heat into a reservoir. [TERM] is used to produce viscous, thick oils with API gravities less than 20. These oils cannot flow unless they are heated and their viscosity is reduced enough to allow flow toward producing wells. During [TERM], crude oil undergoes physical and chemical changes because of the effects of the heat supplied. Physical properties such as viscosity, specific gravity and interfacial tension are altered. The chemical changes involve different reactions such as cracking, which is the destruction of carbon-carbon bonds to generate lower molecular weight compounds, and dehydrogenation, which is the rupture of carbon-hydrogen bonds. [TERM] is a major branch of enhanced oil recovery processes and can be subdivided in two types: hot fluid injection such as steam injection (steamflood or cyclic steam injection) and hot waterflooding and in-situ combustion processes.', accepted_answers = array['TEOR', 'thermal recovery']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'TEOR';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'TEOR' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('thermal recovery'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('thermal recovery');
update public.questions set question = '[Enhanced Oil Recovery] Another term for [TERM], in a displacement process, the ratio of the cumulative height of the vertical sections of the pay zone that are contacted by injection fluid to the total vertical pay zone height. [TERM] (EI) strongly depends on parameters such as mobility ratio and total volume of fluid injected. Nonuniform permeability may cause an irregular front that affects the [TERM] because the injected fluid flows faster in high-permeability zones than in low-permeability zones.', accepted_answers = array['vertical displacement efficiency', 'vertical sweep efficiency']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'vertical sweep efficiency';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'vertical sweep efficiency' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('vertical displacement efficiency'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('vertical displacement efficiency');
update public.questions set question = '[Enhanced Oil Recovery] Another term for [TERM], a measure of the effectiveness of an enhanced oil recovery process that depends on the volume of the reservoir contacted by the injected fluid. The [TERM] is an overall result that depends on the injection pattern selected, off-pattern wells, fractures in the reservoir, position of gas-oil and oil/water contacts, reservoir thickness, permeability and areal and vertical heterogeneity, mobility ratio, density difference between the displacing and the displaced fluid, and flow rate.', accepted_answers = array['volumetric displacement efficiency', 'volumetric sweep efficiency']::text[] where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'volumetric sweep efficiency';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer = 'volumetric sweep efficiency' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('volumetric displacement efficiency'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Enhanced Oil Recovery' and source = 'SLB Glossary' and retired_at is null) and answer in ('volumetric displacement efficiency');

-- Formation Evaluation
update public.questions set question = '[Formation Evaluation] Another term for [TERM], the result of certain drilling conditions that cause the borehole to take the shape of a corkscrew. Most logging tools are much longer than the wavelength of the corkscrew, and therefore see it as a change in standoff or a change in hole size. For this reason, the corkscrew is often observed as a wave on the caliper log. A [TERM] affects measurements sensitive to standoff, such as induction and neutron porosity, and may affect pad tools, if they cannot follow the changes.', accepted_answers = array['corkscrew hole', 'spiral borehole']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'corkscrew hole';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'corkscrew hole' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('spiral borehole'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('spiral borehole');
update public.questions set question = '[Formation Evaluation] Also known as [TERM], the point in a well from which depth is measured. Alternatively, the [TERM] is the point at which the depth is defined as being zero. It is typically the top of the kelly bushing or the level of the drill floor on the rig that is used to drill the well. The depth measured from that point is the measured depth (MD) for the well. Even when the drilling rig has been removed, all subsequent measurements and operations in the well are still tied in to the same [TERM]. However, for multiwell studies, the depths are normally shifted to the permanent datum. The [TERM] and its elevation above the permanent datum are recorded on the log heading. In some contexts, the term may refer to any point from which depth is measured.', accepted_answers = array['depth datum', 'depth reference']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'depth datum';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'depth datum' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('depth reference'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('depth reference');
update public.questions set question = '1. (n.) [Geology] The interconnected pore volume or void space in a rock that contributes to fluid flow or permeability in a reservoir. [TERM] excludes isolated pores and pore volume occupied by water adsorbed on clay minerals or other grains. Total porosity is the total void space in the rock whether or not it contributes to fluid flow. [TERM] is typically less than total porosity. | 2. (n.) [Formation Evaluation] In the original definition of core analysts, the volume of connected pores in a unit volume of rock. [TERM] in this sense is the total porosity less the isolated porosity. It is the porosity measured by most core analysis techniques that do not involve disaggregating the sample. In these techniques, the porosity is usually measured on totally dried core samples. Drying removes most of the clay-bound water. In log interpretation, [TERM] means the total porosity less the clay-bound water. The definition is based on the analysis of shaly formations, in which the clay-bound water is considered immobile and hence ineffective. Isolated porosity is rare in such formations and is ignored, being included in the [TERM]. [TERM] on dried core samples is therefore greater than [TERM] from log analysis, and close to the total porosity from log analysis. In humidity-dried cores, part of the clay-bound water is not removed, and the difference is reduced. In some usage, the capillary-bound water is not considered part of the [TERM]. In this case [TERM] is synonymous with [TERM]. [TERM] is measured in volume/volume, percent or porosity units, p.u.', accepted_answers = array['effective porosity', 'free fluid', 'free water']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'free fluid';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'free fluid' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('effective porosity', 'free water'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('effective porosity', 'free water');
update public.questions set question = '1. (n.) [Geophysics] The delay or difference in the arrival time of seismic events that can result from weathering of the rocks or variations in geologic structures in the subsurface. | 2. (n.) [Geophysics] A term used in seismic processing to describe the interval between the zero-time of a crosscorrelation between two traces and the point of maximum correlation. | 3. (n.) [Geophysics] The time delay of the onset of one sinusoidal oscillation, or frequency component of a trace, relative to another. Also known as a "phase-[TERM]." | 4. (n.) [[TERM]] The distance between the static measure point and the dynamic measure point of a logging measurement. For nuclear logs and any others that must be recorded over a significant time period, there is a difference between the measure point with the tool stationary and moving. If the tool is moving during this period, the effective center of measurement will be a certain distance from the point at which the measurement started. This distance is the [TERM]. The [TERM] depends on the logging speed and the sampling interval.', accepted_answers = array['formation evaluation', 'lag']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'lag';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'lag' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('formation evaluation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('formation evaluation');
update public.questions set question = '[Formation Evaluation] The resistivity of a formation measured by flowing current in a horizontal plane. In anisotropic formations the horizontal and vertical resistivities are different. In a vertical well, wireline induction logs and measurements-while-drilling propagation logs measure the [TERM], whereas laterologs measure the [TERM] with some component of the vertical. In deviated and horizontal wells, all these logs measure some mixture of both vertical and [TERM].', accepted_answers = array['horizontal resistivity', 'Rh']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'Rh';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'Rh' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('horizontal resistivity'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('horizontal resistivity');
update public.questions set question = '[Formation Evaluation] Analysis performed by downhole tools to determine physical and chemical properties of fluids. Typical analyses that can be performed downhole include basic density and viscosity measurements at sampling pressure and temperature.', accepted_answers = array['in situ fluid analysis', 'in-situ fluid analysis']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'in situ fluid analysis';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'in situ fluid analysis' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('in-situ fluid analysis'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('in-situ fluid analysis');
update public.questions set question = '[Formation Evaluation] Display ranges chosen for the density and neutron porosity logs such that the two curves will overlay at all porosity values providing the matrix is pure calcite and the pores are filled with fresh water. The most common overlay spans two tracks, with the density reading from 1.95 to 2.95 g/cm3, and the neutron in limestone porosity units from 0.45 to −0.15 vol/vol.', accepted_answers = array['limestone compatible scale', 'limestone-compatible scale']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'limestone compatible scale';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'limestone compatible scale' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('limestone-compatible scale'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('limestone-compatible scale');
update public.questions set question = '[Formation Evaluation] Log recorded by a sonic tool with a longer transmitter-to-receiver spacing (generally 10 to 15 ft) than a standard sonic tool. The rock near the borehole is sometimes altered by drilling fluids, stress relief, or both, causing a thin zone whose velocity is lower than that of the true formation. With standard spacings, the wave traveling through the altered zone may arrive first at the receiver, since this zone is closer to both transmitter and receiver. The increased spacing permits the wave traveling through the true formation to arrive first and be measured. The depth of investigation varies with slowness and transmitter-receiver spacing but is of the order of 2 to 3 ft. An increased transmitter-to-receiver spacing also allows better separation of waveforms relating to different acoustic waves, such as compressional, shear and Stoneley arrivals.', accepted_answers = array['long spacing sonic log', 'long-spacing sonic log']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'long spacing sonic log';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'long spacing sonic log' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('long-spacing sonic log'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('long-spacing sonic log');
update public.questions set question = '[Formation Evaluation] A neutron interaction in which the neutron is absorbed by the target nucleus, producing an isotope in an excited state. The activated isotope de-excites instantly through the emission of characteristic gamma rays. [TERM], also called [TERM], usually occurs at low thermal energies at which the neutrons have about the same energy as the surrounding matter, typically below 0.4 eV (0.025 eV at room temperature). Some elements are better thermal absorbers than others. [TERM] is an important principle behind the pulsed [TERM] log, the elemental capture spectroscopy log, the pulsed neutron spectroscopy log and the thermal neutron porosity measurement.', accepted_answers = array['neutron capture', 'thermal capture']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'neutron capture';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'neutron capture' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('thermal capture'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('thermal capture');
update public.questions set question = '[Formation Evaluation, Reservoir Characterization] Abbreviation for [TERM]. Fraction of pore volume occupied by oil at any location in a reservoir at any time during its life. [TERM] has no petrophysical significance beyond an assessment of the amount of oil remaining in the rock. Considered a snapshot of the reservoir, this assessment depends on the location in the reservoir and time of the measurement. This saturation is measured without regard to the displacement process or processes that produced it. [TERM] ([TERM]) may be calculated from 1 − Sxo, where Sxo is the invaded zone, or flushed zone, water saturation.', accepted_answers = array['remaining oil saturation', 'ROS']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'ROS';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'ROS' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('remaining oil saturation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('remaining oil saturation');
update public.questions set question = '[Formation Evaluation, Reservoir Characterization] Abbreviation for [TERM]. Fraction of pore volume occupied by oil at the end of oil displacement that used a specific fluid. This reservoir engineering quantity signifies the ultimate recovery under a given displacement process and represents the endpoint of the relative permeability curves in reservoir simulation. The [TERM] quantity is the saturation achieved after an infinite number of pore volumes of the displacing fluid have flowed through a particular portion of reservoir rock. To define [TERM], the displacement method and the type, volume, direction and velocity of the displacing fluid must be known. [TERM] is the ratio of the immobile residual oil volume divided by the effective porosity.', accepted_answers = array['residual oil saturation', 'SOR']::text[] where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'SOR';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer = 'SOR' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('residual oil saturation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Formation Evaluation' and source = 'SLB Glossary' and retired_at is null) and answer in ('residual oil saturation');

-- Geology
update public.questions set question = '1. (n.) [Geology] Abbreviation for [TERM]. [TERM], predominantly methane [CH4], generated during coal formation and adsorbed in coal. [TERM] adsorbs to the surfaces of matrix pores within the coal and natural fractures, or cleats, as reservoir pressure increases. Production of [TERM] from coal requires decreasing the pore pressure below the coal’s desorption pressure so that methane will desorb from surfaces, diffuse through the coal matrix and become free gas. Because the diffusivity and permeability of the coal matrix are ultralow, coal must have an extensive cleat system to ensure adequate permeability and flow of methane to wellbores at economic production rates. Coal seams are typically saturated with water. Consequently, the coal must be dewatered for efficient gas production. Dewatering reduces the hydrostatic pressure and promotes gas desorption from coal. As dewatering progresses, gas production often increases at a rate governed by how quickly gas desorbs from coal, the permeability of the cleat and the relative permeability of the gas-water system in the cleat. Eventually, the rate and amount of gas desorption decreases as the coal seam is depleted of its gas, and production declines. Coal seams with no water (dry coal) have been discovered and commercially exploited. In these reservoirs, the adsorbed gas is held in place by free gas in the cleats. Consequently, gas production consists of both free gas from the cleat system and desorbed gas from the matrix. | 2. (n.) [Geophysics] Abbreviation for common source gather. A display of seismic traces that share a source.', accepted_answers = array['CBM', 'coal seam gas', 'coalbed methane', 'CSG', 'natural gas']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'CBM';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'CBM' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('coal seam gas', 'coalbed methane', 'CSG', 'natural gas'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('coal seam gas', 'coalbed methane', 'CSG', 'natural gas');
update public.questions set question = '[Geology] Water that occurs naturally within the pores of rock. Water from fluids introduced to a formation through drilling or other interference, such as mud and seawater, does not constitute [TERM]. [TERM], or formation water, might not have been the water present when the rock originally formed. In contrast, [TERM] is the water trapped in the pores of a rock during its formation, also called fossil water. Antonyms: [TERM]', accepted_answers = array['connate water', 'interstitial water']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'connate water';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'connate water' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('interstitial water'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('interstitial water');
update public.questions set question = '[Geology] Located down the slope of a dipping plane or surface. In a dipping (not flat-lying) hydrocarbon reservoir that contains gas, oil and water, the gas is updip, the gas-oil contact is [TERM] from the gas, and the oil-water contact is still farther [TERM]. Antonyms: updip', accepted_answers = array['down dip', 'downdip']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'downdip';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'downdip' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('down dip'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('down dip');
update public.questions set question = '[Geology] The termination of more steeply dipping overlying strata against a surface or underlying strata that have lower apparent dips; a term used to describe a particular geometry of reflections in seismic data in sequence stratigraphy.', accepted_answers = array['down lap', 'downlap']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'downlap';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'downlap' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('down lap'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('down lap');
update public.questions set question = '1. (n.) [Geology] Abbreviation for [TERM], a bounding surface in a reservoir above which predominantly gas occurs and below which predominantly oil occurs. Gas and oil are miscible, so the contact between gas and oil is transitional, forming a zone containing a mix of gas and oil. | 2. (n.) [Well Completions] Abbreviation for [TERM], the interface between the gas and oil phases present in a reservoir formation. During the production of a well, the [TERM] may move, resulting in undesirable production conditions such as a high proportion of gas that may be too much for surface processing facilities. Monitoring the gas-oil and oil-water contacts is a key element of good reservoir management practices.', accepted_answers = array['gas-oil contact', 'GOC']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'GOC';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'GOC' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas-oil contact'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas-oil contact');
update public.questions set question = '[Geology] Abbreviation for [TERM], a bounding surface in a reservoir above which predominantly gas occurs and below which predominantly water occurs. Gas and water are somewhat miscible, so the contact between gas and water is not necessarily sharp and there is typically a transition zone between 100% gas and 100% water in reservoirs.', accepted_answers = array['gas-water contact', 'GWC']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'GWC';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'GWC' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas-water contact'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas-water contact');
update public.questions set question = '[Geology] The pressure of the weight of overburden, or overlying rock, on a formation; also called [TERM].', accepted_answers = array['geostatic pressure', 'lithostatic pressure']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'geostatic pressure';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'geostatic pressure' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('lithostatic pressure'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('lithostatic pressure');
update public.questions set question = '[Drilling Fluids, Geology] Also known as [TERM], the rate of increase in temperature per unit depth in the Earth. Although the [TERM] varies from place to place, it averages 25 to 30 °C/km [15 °F/1000 ft]. [TERM] sometimes increase dramatically around volcanic areas. It is particularly important for drilling fluids engineers to know the [TERM] in an area when they are designing a deep well. The downhole temperature can be calculated by adding the surface temperature to the product of the depth and the [TERM].', accepted_answers = array['geothermal gradient', 'temperature gradient', 'thermal gradient']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'thermal gradient';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'thermal gradient' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('geothermal gradient', 'temperature gradient'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('geothermal gradient', 'temperature gradient');
update public.questions set question = '[Geology] An area of the subsurface where source rock has reached appropriate conditions of pressure and temperature to generate hydrocarbons; also known as source kitchen, [TERM] or gas kitchen.', accepted_answers = array['hydrocarbon kitchen', 'oil kitchen']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'oil kitchen';
