update public.questions set question = '[Geology] In the original location or position, such as a large outcrop that has not been disturbed by faults or landslides. Tests can be performed [TERM] in a reservoir to determine its pressure and temperature and fluid properties.', accepted_answers = array['in situ', 'in-situ']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'in situ';
