update public.questions set question = '[Geophysics, Geology] Also known as [TERM], a near-surface, possibly unconsolidated layer of low seismic velocity. The base of the [TERM] commonly coincides with the water table and a sharp increase in seismic velocity. The [TERM] typically has air-filled pores.', accepted_answers = array['low velocity layer', 'low-velocity layer', 'weathered layer']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'weathered layer';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'weathered layer' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('low velocity layer', 'low-velocity layer'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('low velocity layer', 'low-velocity layer');
update public.questions set question = '[Geology] Abbreviation for [TERM], the periodic switching of the magnetic north and south poles of the Earth throughout time, probably as a result of movement of fluid within the Earth''s core. The onset and duration of the many episodes of reversed polarity have been documented by examining the polarity of magnetic minerals within rocks of different ages from around the world, particularly in basalts or igneous rocks of the oceanic crust. Oceanic basalts record the Earth''s magnetic field as they solidify from molten lava symmetrically on each side of the midoceanic ridges. These data have been compiled to create a time scale known as the geomagnetic polarity time scale (GPTS). In the oil field, borehole recordings allow direct correlation to GPTS and well-to-well correlations.', accepted_answers = array['magnetic reversal sequence', 'MRS']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'MRS';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'MRS' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('magnetic reversal sequence'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('magnetic reversal sequence');
update public.questions set question = '1. (adj.) [Geology] Pertaining to an [TERM], an accumulation, pool or group of pools of oil in the subsurface. An [TERM] consists of a reservoir in a shape that will trap hydrocarbons and that is covered by an impermeable or sealing rock. Typically, industry professionals use the term with an implied assumption of economic size. | 2. (adj.) [Geology] Pertaining to the surface area above a subsurface oil accumulation.', accepted_answers = array['oil field', 'oilfield']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'oilfield';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'oilfield' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('oil field'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('oil field');
update public.questions set question = '[Geology] The quality of a source rock that makes it more likely to generate oil than gas. The nature of the organic matter (kerogen) in source rocks varies from coaly, plant-like material commonly found in terrestrial source rocks to algal or other marine material that makes up marine source rocks. Marine source rocks are commonly [TERM].', accepted_answers = array['oil prone', 'oil-prone']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'oil prone';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'oil prone' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('oil-prone'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('oil-prone');
update public.questions set question = '[Geology] Abbreviation for [TERM], a bounding surface in a reservoir above which predominantly oil occurs and below which predominantly water occurs. Although oil and water are immiscible, the contact between oil and water is commonly a transition zone and there is usually irreducible water adsorbed by the grains in the rock and immovable oil that cannot be produced. The [TERM] is not always a flat horizontal surface, but instead might be tilted or irregular.', accepted_answers = array['oil-water contact', 'OWC']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'OWC';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'OWC' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('oil-water contact'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer in ('oil-water contact');
update public.questions set question = '1. (n.) [Geology] A type of stratigraphic trap. The termination by thinning or tapering out ("pinching out") of a reservoir against a nonporous sealing rock creates a favorable geometry to trap hydrocarbons, particularly if the adjacent sealing rock is a source rock such as a shale. | 2. (n.) [Geology] A reduction in bed thickness resulting from onlapping stratigraphic sequences.', accepted_answers = array['pinch out', 'pinch-out']::text[] where topic_id in (select id from public.topics where name = 'Geology' and source = 'SLB Glossary' and retired_at is null) and answer = 'pinch out';
