update public.questions set question = '[Geophysics] Another term for [TERM], the product of density and seismic velocity, which varies among different rock layers, commonly symbolized by Z. The difference in [TERM] between rock layers affects the reflection coefficient.', accepted_answers = array['acoustic impedance', 'seismic impedance']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'seismic impedance';
