delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('acoustic impedance');
update public.questions set question = '[Geophysics] Abbreviation for [TERM]. A system to automatically control the gain, or the increase in the amplitude of an electrical signal from the original input to the amplified output. [TERM] is commonly used in seismic processing to improve visibility of late-arriving events in which attenuation or wavefront divergence has caused amplitude decay.', accepted_answers = array['AGC', 'automatic gain control']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'AGC';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'AGC' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('automatic gain control'));
