update public.questions set question = '[Geophysics] Abbreviation for [TERM]. Variation in seismic reflection amplitude with change in distance between shotpoint and receiver that indicates differences in lithology and fluid content in rocks above and below the reflector. [TERM] analysis is a technique by which geophysicists attempt to determine thickness, porosity, density, velocity, lithology and fluid content of rocks. Successful [TERM] analysis requires special processing of seismic data and seismic modeling to determine rock properties with a known fluid content. With that knowledge, it is possible to model other types of fluid content. A gas-filled sandstone might show increasing amplitude with offset, whereas a coal might show decreasing amplitude with offset. A limitation of [TERM] analysis using only P-energy is its failure to yield a unique solution, so [TERM] results are prone to misinterpretation. One common misinterpretation is the failure to distinguish a gas-filled reservoir from a reservoir having only partial gas saturation ("fizz water"). However, [TERM] analysis using source-generated or mode-converted shear wave energy allows differentiation of degrees of gas saturation. [TERM] analysis is more successful in young, poorly consolidated rocks, such as those in the Gulf of Mexico, than in older, well-cemented sediments.', accepted_answers = array['amplitude variation with offset', 'AVO', 'AVOAZ']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'AVO';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'AVO' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('amplitude variation with offset', 'AVOAZ'));
