update public.questions set question = '[Geophysics] A modeling technique to assess the geologic history of rock layers through the use of geologic cross sections or seismic sections. Removal of the youngest layers of rock at the top of the section allows restoration of the underlying layers to their initial, undisturbed configurations. Successively older layers can be sequentially removed to further assess the effects of compaction, development of geologic structures, and other processes on an area.', accepted_answers = array['back stripping', 'back-stripping']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'back stripping';
