update public.questions set question = '1. (n.) [Geology] Abbreviation for coal seam gas. Natural gas, predominantly methane [CH4], generated during coal formation and adsorbed in coal. Natural gas adsorbs to the surfaces of matrix pores within the coal and natural fractures, or cleats, as reservoir pressure increases. Production of natural gas from coal requires decreasing the pore pressure below the coal’s desorption pressure so that methane will desorb from surfaces, diffuse through the coal matrix and become free gas. Because the diffusivity and permeability of the coal matrix are ultralow, coal must have an extensive cleat system to ensure adequate permeability and flow of methane to wellbores at economic production rates. Coal seams are typically saturated with water. Consequently, the coal must be dewatered for efficient gas production. Dewatering reduces the hydrostatic pressure and promotes gas desorption from coal. As dewatering progresses, gas production often increases at a rate governed by how quickly gas desorbs from coal, the permeability of the cleat and the relative permeability of the gas-water system in the cleat. Eventually, the rate and amount of gas desorption decreases as the coal seam is depleted of its gas, and production declines. Coal seams with no water (dry coal) have been discovered and commercially exploited. In these reservoirs, the adsorbed gas is held in place by free gas in the cleats. Consequently, gas production consists of both free gas from the cleat system and desorbed gas from the matrix. | 2. (n.) [Geophysics] Abbreviation for [TERM]. A display of seismic traces that share a source.', accepted_answers = array['common source gather', 'common-source gather', 'CSG']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'CSG';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'CSG' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('common source gather', 'common-source gather'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('common source gather', 'common-source gather');
update public.questions set question = '[Geophysics, Formation Evaluation] Also called [TERM], the amount of time for a wave to travel a certain distance, proportional to the reciprocal of velocity, typically measured in microseconds per foot by an acoustic log and symbolized by t or DT. P-wave [TERM] for common sedimentary rock types range from 43 (dolostone) to 160 (unconsolidated shales) microseconds per foot, and can be distinguished from measurements of steel casing, which has a consistent transit time of 57 microseconds per foot.', accepted_answers = array['delta t', 'interval transit time', 'slowness']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'delta t';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'delta t' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('interval transit time', 'slowness'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('interval transit time', 'slowness');
update public.questions set question = '[Geophysics] Also known as [TERM], a method of seismic migration that uses the integral form (Kirchhoff equation) of the wave equation. All methods of seismic migration involve the backpropagation (or continuation) of the seismic wavefield from the region where it was measured (Earth''s surface or along a borehole) into the region to be imaged. In [TERM], this is done by using the Kirchhoff integral representation of a field at a given point as a (weighted) superposition of waves propagating from adjacent points and times. Continuation of the wavefield requires a background model of seismic velocity, which is usually a model of constant or smoothly varying velocity. Because of the integral form of [TERM], its implementation reduces to stacking the data along curves that trace the arrival time of energy scattered by image points in the earth.', accepted_answers = array['diffraction stack', 'Kirchhoff migration']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'diffraction stack';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'diffraction stack' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('Kirchhoff migration'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('Kirchhoff migration');
update public.questions set question = '[Geophysics] A technique for acquiring a vertical seismic profile that uses the noise of the drill bit as a source and receivers laid out along the ground or seabed. In deep water, the receiver arrays can be deployed vertically. Acquisition and processing are typically more challenging than in the more conventional types of VSPs, but the technique can yield time-depth information and, less frequently, reflection information, while the well is being drilled. The information from a drill-noise VSP can be used to improve time-depth conversions while drilling, decide where to set casing in a well and evaluate drilling hazards, such as anomalous pore pressure.', accepted_answers = array['drill noise vertical seismic profile', 'drill-noise vertical seismic profile']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'drill noise vertical seismic profile';
