update public.questions set question = '[Geophysics] Any one of a set of constants, also known as [TERM], that defines the properties of material that undergoes stress, deforms, and then recovers and returns to its original shape after the stress ceases. The [TERM] include the bulk modulus, Lame constant, Poisson''s ratio, shear modulus, and Young''s modulus. [TERM] are important in seismology because the velocity of waves depends on the [TERM] and density of the rock.', accepted_answers = array['elastic constants', 'elastic moduli', 'modulus of elasticity']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'elastic moduli';
