update public.questions set question = '[Geophysics] A situation in interpretation of seismic data in which predicted and actual values differ, or when an interpreted reflection does not close, or tie, when interpreting intersecting lines; or when interpreted seismic data do not match results of drilling a well. [TERM] commonly occur when data of different phases, rather than uniformly zero-phase data, are interpreted together, or data that have different datum corrections are tied. [TERM] are described as static if they involve a bulk shift of data (as in the case of tying seismic sections with different datum corrections) or dynamic if the magnitude of the [TERM] varies with time (as in the case of data that have been migrated differently).', accepted_answers = array['mis tie', 'mis-tie']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'mis tie';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'mis tie' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('mis-tie'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('mis-tie');
update public.questions set question = '[Geophysics] Another term for [TERM], an elastic constant for the ratio of shear stress to shear strain. The [TERM] is one of the Lamé constants. It can be expressed mathematically as follows: μ = τ / γ = (ΔF/A) / (ΔL/L), where μ = [TERM] τ = Shear stress = ΔF/A ΔF = Increment of shear force A = Area acted on by the shear force γ = Shear strain = ΔL/L ΔL = Increment of transverse displacement parallel to A L = Original length.', accepted_answers = array['modulus of rigidity', 'shear modulus']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'shear modulus';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'shear modulus' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('modulus of rigidity'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('modulus of rigidity');
update public.questions set question = '[Geophysics] Another term for [TERM], a bulk shift of a seismic trace in time during seismic processing. A common [TERM] is the weathering correction, which compensates for a layer of low seismic velocity material near the surface of the Earth. Other corrections compensate for differences in topography and differences in the elevations of sources and receivers.', accepted_answers = array['near-surface correction', 'static correction', 'statics']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'statics';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'statics' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('near-surface correction', 'static correction'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('near-surface correction', 'static correction');
update public.questions set question = '[Geophysics] Abbreviation for [TERM], a type of vertical seismic profile in which the source is located at an offset from the drilling rig during acquisition. This allows imaging to some distance away from the wellbore.', accepted_answers = array['offset vertical seismic profile', 'offset VSP']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'offset VSP';
