delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('offset vertical seismic profile');
update public.questions set question = '[Geophysics] An elastic body wave or sound wave in which particles oscillate in the direction the wave propagates. [TERM] are the waves studied in conventional seismic data. [TERM] incident on an interface at other than normal incidence can produce reflected and transmitted S-waves, in that case known as converted waves.', accepted_answers = array['p wave', 'P-wave']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'p wave';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'p wave' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('P-wave'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('P-wave');
update public.questions set question = '[Geophysics] Another term for [TERM], the ratio of amplitude of the reflected wave to the incident wave, or how much energy is reflected. If the wave has normal incidence, then its [TERM] can be expressed as: R = (ρ2V2 − ρ1V1) / (ρ2V2 + ρ1V1), where R = [TERM], whose values range from −1 to +1 ρ1 = density of medium 1 ρ2 = density of medium 2 V1 = velocity of medium 1 V2 = velocity of medium 2. Typical values of R are approximately −1 from water to air, meaning that nearly 100% of the energy is reflected and none is transmitted; ~0.5 from water to rock; and ~0.2 for shale to sand. At non-normal incidence, the [TERM] defined as a ratio of amplitudes depends on other parameters, such as the shear velocities, and is described as a function of incident angle by the Zoeppritz equations.', accepted_answers = array['reflection coefficient', 'reflectivity']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'reflectivity';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'reflectivity' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('reflection coefficient'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('reflection coefficient');
update public.questions set question = '[Geophysics] One of a number of locations or stations at the surface of the Earth at which a seismic source is activated.', accepted_answers = array['shot point', 'shotpoint']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'shotpoint';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'shotpoint' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('shot point'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('shot point');
update public.questions set question = '[Geophysics] Steps in seismic processing to compensate for attenuation, spherical divergence and other effects by adjusting the amplitude of the data. The goal is to get the data to a state where the reflection amplitudes relate directly to the change in rock properties giving rise to them.', accepted_answers = array['true amplitude recovery', 'true-amplitude recovery']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'true amplitude recovery';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'true amplitude recovery' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('true-amplitude recovery'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('true-amplitude recovery');
update public.questions set question = '[Geophysics] The marine equivalent of ground roll. [TERM] consists of a pseudo-Rayleigh wave traveling along the interface of the water and the seafloor. As the use of seabed receiver systems increases, noise from [TERM] has become more of a concern.', accepted_answers = array['water bottom roll', 'water-bottom roll']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'water bottom roll';
