delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('water-bottom roll');
update public.questions set question = '[Geophysics] Pertaining to seismic data whose wavelet is symmetrical about zero time. Deconvolution during seismic processing can convert data of mixed phase to [TERM] data, but is not always successful. [TERM] data tend to provide sharper definition and less distortion between stratigraphic features in the subsurface, such as sand and shale layers.', accepted_answers = array['zero phase', 'zero-phase']::text[] where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer = 'zero phase';
