delete from public.questions where topic_id in (select id from public.topics where name = 'Geophysics' and source = 'SLB Glossary' and retired_at is null) and answer in ('zero-phase');

-- Heavy Oil
update public.questions set question = '[Enhanced Oil Recovery, Heavy Oil] A non-thermal primary process for producing heavy oil, also called [TERM]. In this method, continuous production of sand improves the recovery of heavy oil from the reservoir. There is both a theoretical basis and physical evidence that, in many cases, wormholes are formed in the unconsolidated sand reservoir, thereby increasing oil productivity. In most cases, an artificial lift system is used to lift the oil with sand.', accepted_answers = array['CHOPS', 'cold heavy oil production with sand']::text[] where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'CHOPS';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'CHOPS' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('cold heavy oil production with sand'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('cold heavy oil production with sand');
update public.questions set question = '[Heavy Oil] A method of thermal recovery in which a well is injected with steam and then subsequently put back on production. A cyclic steam-injection process includes three stages. The first stage is injection, during which a slug of steam is introduced into the reservoir. The second stage, or [TERM], requires that the well be shut in for several days to allow uniform heat distribution to thin the oil. Finally, during the third stage, the thinned oil is produced through the same well. The cycle is repeated as long as oil production is profitable. [TERM] is used extensively in heavy-oil reservoirs, tar sands, and in some cases to improve injectivity prior to steamflood or in situ combustion operations. [TERM] is also called [TERM] or the huff ''n'' puff (slang) method.', accepted_answers = array['cyclic steam injection', 'soak phase', 'steam soak']::text[] where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'soak phase';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'soak phase' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('cyclic steam injection', 'steam soak'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('cyclic steam injection', 'steam soak');
update public.questions set question = '[Enhanced Oil Recovery, Heavy Oil] A method of thermal recovery in which fire is generated inside the reservoir by injecting a gas containing oxygen, such as air. A special heater in the well ignites the oil in the reservoir and starts a fire. The heat generated by burning the heavy hydrocarbons in place produces hydrocarbon cracking, vaporization of light hydrocarbons and reservoir water in addition to the deposition of heavier hydrocarbons known as coke. As the fire moves, the burning front pushes ahead a mixture of hot combustion gases, steam and hot water, which in turn reduces oil viscosity and displaces oil toward production wells. Additionally, the light hydrocarbons and the steam move ahead of the burning front, condensing into liquids, which adds the advantages of miscible displacement and hot waterflooding. [TERM] is also known as fire flooding or fireflood.', accepted_answers = array['in situ combustion', 'in-situ combustion']::text[] where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'in situ combustion';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'in situ combustion' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('in-situ combustion'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('in-situ combustion');
update public.questions set question = '[Heavy Oil, Enhanced Oil Recovery] Abbreviation for thermal enhanced oil recovery, also known as [TERM], a general term for injection processes that introduce heat into a reservoir. [TERM] is used to produce viscous, thick oils with API gravities less than 20. These oils cannot flow unless they are heated and their viscosity is reduced enough to allow flow toward producing wells. During [TERM], crude oil undergoes physical and chemical changes because of the effects of the heat supplied. Physical properties such as viscosity, specific gravity and interfacial tension are altered. The chemical changes involve different reactions such as cracking, which is the destruction of carbon-carbon bonds to generate lower molecular weight compounds, and dehydrogenation, which is the rupture of carbon-hydrogen bonds. [TERM] is a major branch of enhanced oil recovery processes and can be subdivided in two types: hot fluid injection such as steam injection (steamflood or cyclic steam injection) and hot waterflooding and in-situ combustion processes.', accepted_answers = array['TEOR', 'thermal recovery']::text[] where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'TEOR';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'TEOR' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('thermal recovery'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('thermal recovery');
update public.questions set question = '[Enhanced Oil Recovery, Heavy Oil] An in-situ combustion method for producing heavy oil. In this technique, the fireflooding starts from a vertical well, while the oil is produced from a horizontal well having its toe in close proximity to the vertical air-injection well. This production method is a modification of conventional fire flooding techniques in which the flame front from a vertical well pushes the oil to be produced from another vertical well.', accepted_answers = array['THAI', 'toe to heel air injection']::text[] where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'THAI';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer = 'THAI' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('toe to heel air injection'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Heavy Oil' and source = 'SLB Glossary' and retired_at is null) and answer in ('toe to heel air injection');

-- Oil and Gas Business
update public.questions set question = '[Oil and Gas Business] The right to receive a reversionary interest at some future time, upon fulfillment of contractually specified conditions. This clause allows a lease owner, lessee, or a nonparticipating partner to reserve the option to participate in a well after it has produced enough to pay the operators expenses of drilling and completing that well. This clause is typically used in farmout agreements to convert the overriding royalty interest of a lease owner, lessee, or nonparticipating partner into a working interest upon payout of the well. When the election to convert the overriding royalty to working interest takes place, it is known as a [TERM] after payout (BIAPO).', accepted_answers = array['back in', 'back-in']::text[] where topic_id in (select id from public.topics where name = 'Oil and Gas Business' and source = 'SLB Glossary' and retired_at is null) and answer = 'back in';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Oil and Gas Business' and source = 'SLB Glossary' and retired_at is null) and answer = 'back in' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Oil and Gas Business' and source = 'SLB Glossary' and retired_at is null) and answer in ('back-in'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Oil and Gas Business' and source = 'SLB Glossary' and retired_at is null) and answer in ('back-in');
update public.questions set question = '[Oil and Gas Business] A provision in an oil, gas, and mineral lease that perpetuates a company''s right to operate a property or concession as long as the property or concession produces a minimum paying quantity of oil or gas. Also abbreviated as [TERM].', accepted_answers = array['HBP', 'held by production']::text[] where topic_id in (select id from public.topics where name = 'Oil and Gas Business' and source = 'SLB Glossary' and retired_at is null) and answer = 'HBP';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Oil and Gas Business' and source = 'SLB Glossary' and retired_at is null) and answer = 'HBP' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Oil and Gas Business' and source = 'SLB Glossary' and retired_at is null) and answer in ('held by production'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Oil and Gas Business' and source = 'SLB Glossary' and retired_at is null) and answer in ('held by production');

-- Perforating
update public.questions set question = '[Perforating] A perforating gun having more than four shots per foot. In addition to providing a greater number of perforations, a [TERM] also improves the phasing, or distribution of perforations, around the wellbore.', accepted_answers = array['high shot density gun', 'high-shot density gun']::text[] where topic_id in (select id from public.topics where name = 'Perforating' and source = 'SLB Glossary' and retired_at is null) and answer = 'high shot density gun';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Perforating' and source = 'SLB Glossary' and retired_at is null) and answer = 'high shot density gun' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Perforating' and source = 'SLB Glossary' and retired_at is null) and answer in ('high-shot density gun'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Perforating' and source = 'SLB Glossary' and retired_at is null) and answer in ('high-shot density gun');
update public.questions set question = '[Perforating] Abbreviation for tubing-conveyed perforating, the use of tubing, drillpipe or coiled tubing to convey perforating guns to the required depth. Initially, the technique was developed as a means for conveying the gun string on the production tubing, with the guns remaining in the well until they are removed during the first workover. The subsequent popularity of highly deviated and horizontal wells increased the requirement for tubing-conveyed perforating as the only means of gaining access to the perforating depth.', accepted_answers = array['TCP', 'tubing-conveyed perforating (TCP)']::text[] where topic_id in (select id from public.topics where name = 'Perforating' and source = 'SLB Glossary' and retired_at is null) and answer = 'TCP';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Perforating' and source = 'SLB Glossary' and retired_at is null) and answer = 'TCP' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Perforating' and source = 'SLB Glossary' and retired_at is null) and answer in ('tubing-conveyed perforating (TCP)'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Perforating' and source = 'SLB Glossary' and retired_at is null) and answer in ('tubing-conveyed perforating (TCP)');

-- Production Facilities
update public.questions set question = '[Production Facilities] A measure of heat energy required to raise the temperature of one pound of water by one degree Fahrenheit. [TERM] is abbreviated as [TERM].', accepted_answers = array['British thermal unit', 'BTU']::text[] where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer = 'BTU';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer = 'BTU' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer in ('British thermal unit'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer in ('British thermal unit');
update public.questions set question = '[Production Facilities] A vessel that separates the well fluids into gas and two types of liquids: oil and water. A [TERM] can be horizontal, vertical or spherical. This type of separator is commonly called a [TERM] because its main use is to remove any free water that can cause problems such as corrosion and formation of hydrates or tight emulsions, which are difficult to break. A [TERM] is commonly called a [TERM] because it can separate gas, oil and free water. The liquids that are discharged from the [TERM] are further treated in vessels called treaters. [TERM] is abbreviated as [TERM].', accepted_answers = array['free-water knockout', 'FWKO', 'three-phase separator']::text[] where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer = 'FWKO';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer = 'FWKO' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer in ('free-water knockout', 'three-phase separator'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer in ('free-water knockout', 'three-phase separator');
update public.questions set question = '[Production Facilities] Abbreviation for [TERM], which is a sea vessel used to transport liquefied petroleum gas (LPG).', accepted_answers = array['liquefied natural gas carrier', 'LNGC']::text[] where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer = 'LNGC';
