update public.questions set question = '[Production Facilities] Another term for [TERM], the amount of time a liquid stays in a vessel. The [TERM] assures that equilibrium between the liquid and gas has been reached at separator pressure. The [TERM] in a separator is determined by dividing the liquid volume inside the vessel by the liquid flow rate. The [TERM] usually varies between 30 seconds and 3 minutes. If a foaming crude is present, the [TERM] could be increased by four times its normal values.', accepted_answers = array['residence time', 'retention time']::text[] where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer = 'residence time';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer = 'residence time' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer in ('retention time'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer in ('retention time');
