update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer = 'TAPS' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Facilities' and source = 'SLB Glossary' and retired_at is null) and answer in ('Trans-Alaska Pipeline System'));
