-- Production Logging
update public.questions set question = '[Production Logging] In a spinner flowmeter, the theoretical minimum fluid velocity required to initiate spinner rotation, assuming the spinner response is linear. The actual fluid velocity required to start spinner rotation is slightly higher because of additional viscous and mechanical effects. The [TERM] is determined by extrapolating the spinner response at higher fluid velocities, where it is known to be nearly linear, back to the value that exists when spinner rotation is zero.', accepted_answers = array['bypass velocity', 'threshold velocity']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'bypass velocity';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'bypass velocity' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('threshold velocity'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('threshold velocity');
update public.questions set question = '[Production Logging] Another term for [TERM], a device for determining the water holdup in a producing well by measuring the capacitance or impedance of the fluid. The [TERM] is used to produce a capacitance log. Since water has a high dielectric constant, and hence capacitance, it can be distinguished from oil or gas. The meter is a coaxial capacitor, with fluid flowing between a central probe and an external cage that act as electrodes. The meter has often been combined with a packer flowmeter or a diverter flowmeter, so that all the fluids in the well pass through the meter.', accepted_answers = array['capacitance meter', 'holdup meter']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'holdup meter';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'holdup meter' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('capacitance meter'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('capacitance meter');
update public.questions set question = '[Production Logging] An in situ record of casing thickness and integrity, to determine whether and to what extent the casing has undergone corrosion. The term refers to an individual measurement, or a combination of measurements using acoustic, electrical, and mechanical techniques, to evaluate the casing thickness and other parameters. The log is usually presented with the basic measurements and an estimate of metal loss. It was first introduced in the early 1960s. Today, the terms casing-evaluation log and pipe-inspection log are used synonymously.', accepted_answers = array['casing inspection log', 'casing-inspection log']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'casing inspection log';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'casing inspection log' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('casing-inspection log'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('casing-inspection log');
update public.questions set question = '[Production Logging] An in situ log of the electrical potential on the inner wall of a casing. The log is used to identify intervals that are susceptible to corrosion. A negative slope in the profile indicates a zone in which current is leaving the casing and therefore acting as an anode. Such zones are susceptible to corrosion. The log was first introduced in the early 1960s. Modern logs are recorded with the tool stationary, and measure the potential difference and casing resistance between several pairs of sensors pushed against the casing wall, and between sensors and surface. The log is usually represented with casing resistance and casing axial current. Sharp increases in casing resistance can indicate corroded zones or even holes in the casing. Decreasing axial current with depth indicates a corroding region.', accepted_answers = array['casing potential profile', 'casing-potential profile']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'casing potential profile';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'casing potential profile' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('casing-potential profile'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('casing-potential profile');
update public.questions set question = '[Production Logging] A technique in which a slug of material is introduced into the flowstream of a producing well to determine the flow rate of one or more of the fluids. The marker has specific properties, such as high neutron capture cross section, that allow it to be detected by sensors of a production logging tool. Some markers are specifically designed to be soluble in only one fluid phase, so that they can be used to produce a phase-velocity log. The term refers to nonradioactive markers, in contrast to the more traditional radioactive markers, or tracers.', accepted_answers = array['chemical marker injection', 'chemical-marker injection']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'chemical marker injection';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'chemical marker injection' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('chemical-marker injection'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('chemical-marker injection');
update public.questions set question = '[Production Logging] A record of the difference in temperature between two vertical points in a well. Most [TERM] are obtained by differentiating a normal temperature log with respect to depth. Some are obtained by recording the difference in temperature between two vertically displaced sensors. Note that the [TERM] and the radial [TERM] are not the same.', accepted_answers = array['differential temperature log', 'differential-temperature log']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'differential temperature log';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'differential temperature log' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('differential-temperature log'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('differential-temperature log');
update public.questions set question = '[Production Logging] Another term for [TERM], a small sensor in a production logging tool that distinguishes between hydrocarbon and water in its vicinity as it is moved up and down a production well. The [TERM] was the first type of local probe to be introduced, appearing initially in the early 1990s. [TERM] measure the local and average holdup of water and give an image of the flow structure across the well. Most [TERM] emit a high-frequency current and measure the amplitude of the signal, and hence the impedance, of the fluid in a small sphere near the probe. The output is designed to be digital, indicating conductance when the probe is in front of water, and no conductance when it is in front of hydrocarbon. The water must have a certain minimum salinity, below which the device will not work.', accepted_answers = array['electric probe', 'electrical impedance probe']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'electric probe';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'electric probe' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('electrical impedance probe'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('electrical impedance probe');
update public.questions set question = '[Production Logging] Referring to a type of spinner flowmeter in which most or all of the fluid flow in the well is diverted over the spinner by a device such as a basket or a packer.', accepted_answers = array['flow concentrating', 'flow-concentrating']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'flow concentrating';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'flow concentrating' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow-concentrating'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow-concentrating');
update public.questions set question = '1. (n.) [Well Workover and Intervention] A device installed in a pump manifold or treating line to measure the fluid flow rate. [TERM] can be used to measure the flow rates of liquid or gas and are available in various configurations and with differing operating principles. | 2. (n.) [Production Logging] A device for measuring in-situ the velocity of fluid flow in a well, usually one completed for production or injection. The most common device is the spinner [TERM], but torque [TERM] and crosscorrelation [TERM] also are used. In the 1940s and 1950s, various other surface-metering techniques were tried, but spinner [TERM] emerged as the most suitable for measuring downhole velocities. Spinner and torque [TERM] measure the average velocity of the fluids crossing the device, while crosscorrelation [TERM] measure the velocity of a particular phase. Although not normally called [TERM], various other techniques measure flow velocity, for example water-flow logs, phase-velocity logs, distributed-temperature logs and even audio measurements. | 3. (n.) [Production Testing] An instrument that measures the flow rate of fluids through a pipeline. There are several types of [TERM], including the differential-pressure meter, orifice meter, positive-displacement meter, vortex meter and multiphase meters.', accepted_answers = array['flow meter', 'flowmeter']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowmeter';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowmeter' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow meter'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow meter');
update public.questions set question = '[Production Logging] An in-situ measurement of the flow profile made by pumping different fluids down the tubing and casing and observing the interface between them. The fluids are normally both water, but one may be fresh and the other salty, or else one may contain some tracer, so that the interface can be detected by a production-logging tool. After the tubing is run to the bottom of the well, an interface is introduced by one of two methods. In the static method, the total flow rate is held constant and the relative flow rate of the two streams is changed. The location of the interface after each change is used to determine the flow profile. In the dynamic method, one fluid is pumped at different rates. The log was used in the 1950s and 1960s but is now used rarely, having been replaced by fluid-density logs and others.', accepted_answers = array['fluid interface log', 'fluid-interface log']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'fluid interface log';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'fluid interface log' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('fluid-interface log'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('fluid-interface log');
update public.questions set question = '[Production Logging] A record of the fraction of gas present at different depths in the borehole. Although several techniques may be used for this purpose, the term usually refers to logs based on one of two principles. In the first, four or more optical probes are used to detect the passage of gas bubbles at different points across the borehole. As with other local probes, holdup is determined by the fraction of time the probe detects gas. In the second technique, a 57Co (cobalt) source emits low-energy gamma rays that undergo backscattering and photoelectric absorption in the borehole fluid before being counted in a detector. The number of counts is related to the fluid density, and can be calibrated in terms of gas holdup. The first technique produces an image of gas holdup along and around the borehole, while the second technique produces a log of the average holdup along the well.', accepted_answers = array['gas holdup log', 'gas-holdup log']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'gas holdup log';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'gas holdup log' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas-holdup log'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas-holdup log');
update public.questions set question = '[Production Logging] An in-situ recording in which a material with high neutron-capture cross section is injected into the flowstream of a production or injection well to determine fluid paths and velocities. The material used is normally borax or water with high salinity, both of which cause a significant increase in the capture cross section measured by a pulsed-neutron log. In the most common application, the material is injected across the producing intervals of a production well. By comparing pulsed neutron logs recorded before and after injection, the injectivity, and hence productivity, of each interval can be estimated. Any cement channels or leaks will also be observed.', accepted_answers = array['injection pulsed neutron log', 'injection/pulsed neutron log']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'injection pulsed neutron log';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'injection pulsed neutron log' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('injection/pulsed neutron log'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('injection/pulsed neutron log');
update public.questions set question = '[Production Logging] A record of elemental concentrations derived from the characteristic energy levels of gamma rays emitted by a nucleus that has been activated by neutron bombardment. In the context of production logging, the term normally refers to the activation of silicon and aluminum to determine the quality of a gravel pack. Silicon and aluminum are activated by a neutron source to produce isotopes that decay with a half-life of 2.3 minutes emitting a 1.78 MeV gamma ray. These gamma rays are counted in a detector placed below the source, with a high count indicating a high quantity of silicon in a sand pack, or aluminum in a bauxite pack. The log is run slowly so that oxygen and other activated elements have decayed before the detector crosses the activated interval. The carbon-oxygen log, elemental-capture spectroscopy log, pulsed-neutron spectroscopy log, aluminum-activation log and the oxygen-activation log are also examples of [TERM].', accepted_answers = array['neutron activation log', 'neutron-activation log']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'neutron activation log';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'neutron activation log' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('neutron-activation log'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('neutron-activation log');
update public.questions set question = '[Production Logging] Referring to a flow or other phenomenon with only one component, normally oil, water or gas.', accepted_answers = array['single phase', 'single-phase']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'single phase';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'single phase' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('single-phase'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('single-phase');
update public.questions set question = '[Production Logging] Another term for velocity-shot measurement, a method of producing a radioactive-tracer log, in which a slug of radioactive material is injected into the flow stream of a production or injection well from one section of a logging tool and observed as it passes one or more gamma ray detectors in another section. The slug, or shot, causes a peak in the gamma ray reading as it passes a detector. The flow velocity is determined from the difference in the time of arrival of the slug at the two detectors, or between ejector and detector. This technique has been applied for many years using radioactive tracers such as iodine. Water-soluble tracers are the most common, but oil- and gas-soluble tracers are also used. Velocity-shot measurements are recorded with the tool stationary. They are more accurate than flowmeters at low flow rates, below approximately 100 bbl/d [16 m3/d]. They are not usually run in production wells because of problems of tracer disposal. In multiphase flow, the tracer most often travels with the continuous phase, thereby giving a type of phase-velocity log.', accepted_answers = array['tracer-ejector measurement', 'velocity shot measurement']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'velocity shot measurement';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'velocity shot measurement' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('tracer-ejector measurement'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('tracer-ejector measurement');
update public.questions set question = '[Production Logging] Another term for [TERM], a two-dimensional display, using colors or different gray scales, of the bubble velocity around the borehole against depth. The x-axis of the image shows different segments of the borehole, normally inside a casing, displayed from the top of the hole clockwise around through the bottom and back to the top again. Depth is in the z-axis, while the values of bubble velocity are represented by different colors or changes from black to white. The [TERM] is constructed from between four and eight local probe measurements using interpolation within constraints. Images, sometimes called maps, are also made for bubble count and holdup.', accepted_answers = array['velocity image', 'velocity map']::text[] where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'velocity map';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer = 'velocity map' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('velocity image'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Logging' and source = 'SLB Glossary' and retired_at is null) and answer in ('velocity image');

