update public.questions set question = '1. (n.) [Drilling] The large-diameter metal pipe that connects the bell nipple under the rotary table to the possum belly at the mud tanks. The [TERM] is simply an inclined, gravity-flow conduit to direct mud coming out the top of the wellbore to the mud surface-treating equipment. When drilling certain highly reactive clays, called "gumbo," the [TERM] may become plugged and require considerable effort by the rig crew to keep it open and flowing. In addition, the [TERM] is usually fitted with a crude paddle-type flow-measuring device commonly called a "flow show" that may give the driller the first indication that the well is flowing. | 2. (n.) [Production Testing] A surface pipeline carrying oil, gas or water that connects the wellhead to a manifold or to production facilities, such as heater-treaters and separators.', accepted_answers = array['flow line', 'flowline']::text[] where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowline';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowline' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow line'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow line');
update public.questions set question = '1. (n.) [Well Workover and Intervention] A device installed in a pump manifold or treating line to measure the fluid flow rate. [TERM] can be used to measure the flow rates of liquid or gas and are available in various configurations and with differing operating principles. | 2. (n.) [Production Logging] A device for measuring in-situ the velocity of fluid flow in a well, usually one completed for production or injection. The most common device is the spinner [TERM], but torque [TERM] and crosscorrelation [TERM] also are used. In the 1940s and 1950s, various other surface-metering techniques were tried, but spinner [TERM] emerged as the most suitable for measuring downhole velocities. Spinner and torque [TERM] measure the average velocity of the fluids crossing the device, while crosscorrelation [TERM] measure the velocity of a particular phase. Although not normally called [TERM], various other techniques measure flow velocity, for example water-flow logs, phase-velocity logs, distributed-temperature logs and even audio measurements. | 3. (n.) [Production Testing] An instrument that measures the flow rate of fluids through a pipeline. There are several types of [TERM], including the differential-pressure meter, orifice meter, positive-displacement meter, vortex meter and multiphase meters.', accepted_answers = array['flow meter', 'flowmeter']::text[] where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowmeter';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowmeter' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow meter'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow meter');
