update public.questions set question = '[Production Testing] Natural gas, mainly methane and ethane, which has been liquefied at cryogenic temperatures. This process occurs at an extremely low temperature and a pressure near the atmospheric pressure. When a gas pipeline is not available to transport gas to a marketplace, such as in a jungle or certain remote regions offshore, the gas may be chilled and converted to [TERM] (a liquid) to transport and sell it. The term is commonly abbreviated as [TERM].', accepted_answers = array['liquefied natural gas', 'LNG']::text[] where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'LNG';
