delete from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('liquefied natural gas');
update public.questions set question = '[Production Testing] Gas mainly composed of propane and butane, which has been liquefied at low temperatures and moderate pressures. The gas is obtainable from refinery gases or after the cracking process of crude oil. [TERM] is also called bottle gas. At atmospheric pressure, it is easily converted into gas and can be used industrially or domestically. The term is commonly abbreviated as [TERM].', accepted_answers = array['liquefied petroleum gas', 'LPG']::text[] where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'LPG';
