delete from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('liquefied petroleum gas');
update public.questions set question = '[Production Testing] Abbreviation for [TERM], a common measure for volume of gas. Standard conditions are normally set at 60 degF and 14.7 psia.', accepted_answers = array['million standard cubic feet', 'MMscf']::text[] where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'MMscf';
