update public.questions set question = '[Production Testing] Components of natural gas that are liquid at surface in field facilities or in gas-processing plants. [TERM] can be classified according to their vapor pressures as low (condensate), intermediate (natural gasoline) and high (liquefied petroleum gas) vapor pressure. [TERM] include propane, butane, pentane, hexane and heptane, but not methane and ethane, since these hydrocarbons need refrigeration to be liquefied. The term is commonly abbreviated as [TERM].', accepted_answers = array['natural gas liquids', 'NGL']::text[] where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'NGL';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'NGL' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('natural gas liquids'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('natural gas liquids');
update public.questions set question = '[Production Testing] A condition in downhole pumping operations that occurs when the stroke length at the subsurface sucker-rod pump is longer than the surface stroke length (polished rod). This phenomenon is caused by the elongation of the rod string because of dynamic loads imposed by the pumping cycle. In this situation, when the upstroke begins at the surface, the downhole pump maybe still be moving downward; when the downstroke begins, the downhole pump is still moving upward. Antonyms: undertravel', accepted_answers = array['over travel', 'overtravel']::text[] where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'overtravel';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'overtravel' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('over travel'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('over travel');
update public.questions set question = '[Enhanced Oil Recovery, Production Testing] Also known as [TERM], the first stage of hydrocarbon production, in which natural reservoir energy, such as gasdrive, waterdrive or gravity drainage, displaces hydrocarbons from the reservoir, into the wellbore and up to surface. Initially, the reservoir pressure is considerably higher than the bottomhole pressure inside the wellbore. This high natural differential pressure drives hydrocarbons toward the well and up to surface. However, as the reservoir pressure declines because of production, so does the differential pressure. To reduce the bottomhole pressure or increase the differential pressure to increase hydrocarbon production, it is necessary to implement an artificial lift system, such as a rod pump, an electrical submersible pump or a gas-lift installation. Production using artificial lift is considered [TERM]. The [TERM] stage reaches its limit either when the reservoir pressure is so low that the production rates are not economical, or when the proportions of gas or water in the production stream are too high. During [TERM], only a small percentage of the initial hydrocarbons in place are produced, typically around 10% for oil reservoirs.', accepted_answers = array['primary production', 'primary recovery']::text[] where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'primary recovery';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'primary recovery' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('primary production'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('primary production');
update public.questions set question = '[Production Testing] An unmanned submersible vehicle controlled from surface. In deepwater operations, [TERM] are used to inspect subsea structures and equipment, and to control or manipulate valves. They can operate at depths from 1,500 to 10,000 ft [457 to 3,048 m]. This term is commonly abbreviated as [TERM].', accepted_answers = array['remotely operated vehicle', 'ROV']::text[] where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'ROV';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'ROV' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('remotely operated vehicle'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Production Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('remotely operated vehicle');

