update public.questions set question = '[Reservoir Characterization, Shale Gas] Also known as [TERM], the gas stored in the pore space of a reservoir rock. Measurement of [TERM] and adsorbed gas, which is the gas accumulated on the surface of another solid material, such as a grain of reservoir rock, allows calculation of gas in place in a reservoir.', accepted_answers = array['interstitial gas', 'pore gas']::text[] where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'pore gas';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'pore gas' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('interstitial gas'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('interstitial gas');
update public.questions set question = '[Reservoir Characterization] A highly simplified description of a geological scenario. Although sometimes used for "quick and dirty" simulation models, this description is often not appropriate for detailed or accurate work. Generally, [TERM] is an oversimplification of actual structure and stratigraphy of a reservoir. It assumes that the reservoir comprises a stack of conformable layers.', accepted_answers = array['layer cake geometry', 'layer-cake geometry']::text[] where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'layer cake geometry';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'layer cake geometry' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('layer-cake geometry'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('layer-cake geometry');
update public.questions set question = '[Formation Evaluation, Reservoir Characterization] Abbreviation for [TERM]. Fraction of pore volume occupied by oil at any location in a reservoir at any time during its life. [TERM] has no petrophysical significance beyond an assessment of the amount of oil remaining in the rock. Considered a snapshot of the reservoir, this assessment depends on the location in the reservoir and time of the measurement. This saturation is measured without regard to the displacement process or processes that produced it. [TERM] ([TERM]) may be calculated from 1 − Sxo, where Sxo is the invaded zone, or flushed zone, water saturation.', accepted_answers = array['remaining oil saturation', 'ROS']::text[] where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'ROS';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'ROS' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('remaining oil saturation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('remaining oil saturation');
update public.questions set question = '1. (n.) [[TERM]] Also called [TERM], a model of a reservoir that incorporates all the characteristics of the reservoir that are pertinent to its ability to store hydrocarbons and also to produce them. [TERM] models are used to simulate the behavior of the fluids within the reservoir under different sets of circumstances and to find the optimal production techniques that will maximize the production. | 2. (n.) [[TERM]] The act of building a reservoir model based on its characteristics with respect to fluid flow.', accepted_answers = array['reservoir characterization', 'reservoir description']::text[] where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'reservoir description';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'reservoir description' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('reservoir characterization'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('reservoir characterization');
update public.questions set question = '[Formation Evaluation, Reservoir Characterization] Abbreviation for [TERM]. Fraction of pore volume occupied by oil at the end of oil displacement that used a specific fluid. This reservoir engineering quantity signifies the ultimate recovery under a given displacement process and represents the endpoint of the relative permeability curves in reservoir simulation. The [TERM] quantity is the saturation achieved after an infinite number of pore volumes of the displacing fluid have flowed through a particular portion of reservoir rock. To define [TERM], the displacement method and the type, volume, direction and velocity of the displacing fluid must be known. [TERM] is the ratio of the immobile residual oil volume divided by the effective porosity.', accepted_answers = array['residual oil saturation', 'SOR']::text[] where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'SOR';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer = 'SOR' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('residual oil saturation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Reservoir Characterization' and source = 'SLB Glossary' and retired_at is null) and answer in ('residual oil saturation');

-- Shale Gas
update public.questions set question = '[Drilling, Shale Gas] Abbreviation for logging while drilling. The measurement of formation properties during the excavation of the hole, or shortly thereafter, through the use of tools integrated into the bottomhole assembly. [TERM], while sometimes risky and expensive, has the advantage of measuring properties of a formation before drilling fluids invade deeply. Further, many wellbores prove to be difficult or even impossible to measure with conventional wireline tools, especially highly deviated wells. In these situations, the [TERM] measurement ensures that some measurement of the subsurface is captured in the event that wireline operations are not possible. Timely [TERM] data can also be used to guide well placement so that the wellbore remains within the zone of interest or in the most productive portion of a reservoir, such as in highly variable shale reservoirs.', accepted_answers = array['formation evaluation while drilling', 'logging-while-drilling', 'LWD']::text[] where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'LWD';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'LWD' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('formation evaluation while drilling', 'logging-while-drilling'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('formation evaluation while drilling', 'logging-while-drilling');
update public.questions set question = '[Shale Gas, Well Completions] An abbreviation for [TERM], a fluid injected into a well as part of a stimulation operation. [TERM] for shale reservoirs usually contain water, proppant, and a small amount of nonaqueous fluids designed to reduce friction pressure while pumping the fluid into the wellbore. These fluids typically include gels, friction reducers, crosslinkers, breakers and surfactants similar to household cosmetics and cleaning products; these additives are selected for their capability to improve the results of the stimulation operation and the productivity of the well.', accepted_answers = array['frac fluid', 'fracturing fluid']::text[] where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac fluid';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac fluid' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('fracturing fluid'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('fracturing fluid');
update public.questions set question = '[Well Completions, Shale Gas, Well Workover and Intervention] Another term for [TERM], a stimulation treatment routinely performed on oil and gas wells in low-permeability reservoirs. Specially engineered fluids are pumped at high pressure and rate into the reservoir interval to be treated, causing a vertical fracture to open. The wings of the fracture extend away from the wellbore in opposing directions according to the natural stresses within the formation. Proppant, such as grains of sand of a particular size, is mixed with the treatment fluid to keep the fracture open when the treatment is complete. [TERM] creates high-conductivity communication with a large area of formation and bypasses any damage that may exist in the near-wellbore area.', accepted_answers = array['frac job', 'hydraulic fracturing']::text[] where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac job';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac job' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydraulic fracturing'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydraulic fracturing');
update public.questions set question = '[Well Completions, Shale Gas] A technique to track the propagation of a hydraulic fracture as it advances through a formation. Microseisms are detected, located, and displayed in time for scientists and engineers to approximate the location and propagation of the hydraulic fracture. Software provides modeling, survey design, microseismic detection and location, uncertainty analysis, data integration, and visualization for interpretation. Computer imagery is used to monitor the activity in 3D space relative to the location of the fracturing treatment. The monitored activities are animated to show progressive fracture growth and the subsurface response to pumping variations. When displayed in real time, the microseismic activity allows one to make changes to the stimulation design to ensure optimal reservoir contact. Also known as [TERM], this technique delivers information about the effectiveness of the stimulation of a reservoir that can be used to enhance reservoir development in shale gas completions.', accepted_answers = array['hydraulic fracture monitoring', 'microseismic monitoring']::text[] where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'microseismic monitoring';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'microseismic monitoring' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydraulic fracture monitoring'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydraulic fracture monitoring');
update public.questions set question = '[Reservoir Characterization, Shale Gas] Also known as [TERM], the gas stored in the pore space of a reservoir rock. Measurement of [TERM] and adsorbed gas, which is the gas accumulated on the surface of another solid material, such as a grain of reservoir rock, allows calculation of gas in place in a reservoir.', accepted_answers = array['interstitial gas', 'pore gas']::text[] where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'pore gas';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer = 'pore gas' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('interstitial gas'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Shale Gas' and source = 'SLB Glossary' and retired_at is null) and answer in ('interstitial gas');

-- Well Completions
update public.questions set question = '1. (n.) [Drilling] Another term for [TERM], the intentional pumping of wellbore fluids down the annulus and back up through the drillpipe. This is the opposite of the normal direction of fluid circulation in a wellbore. Since the inside volume of the drillpipe is considerably less than the volume of the annulus outside of the drillpipe, [TERM] can bring bottomhole fluids to the surface faster than normal circulation for a given flow rate. Two potential hazards of [TERM] include lifting cuttings and other junk into the drillstring and the rapid flow of reservoir fluids to the surface in a kick situation. | 2. (vb.) [Well Completions] To conduct [TERM]—that is, to circulate fluid down the wellbore annulus, with returns being made up the tubing string. [TERM] is often used to remove debris from the wellbore because the high fluid flow rate inside the tubing string enables the recovery of large or dense debris particles that are difficult or impossible to remove with conventional circulation.', accepted_answers = array['back wash', 'backwash', 'reverse circulation', 'reversing out']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'backwash';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'backwash' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('back wash', 'reverse circulation', 'reversing out'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('back wash', 'reverse circulation', 'reversing out');
update public.questions set question = '[Well Completions] Describing a mechanism or system that is actuated by a ball that is dropped or pumped through the tubing string. Once located on a landing seat, the tool mechanism is generally actuated by hydraulic pressure.', accepted_answers = array['ball operated', 'ball-operated']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'ball operated';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'ball operated' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('ball-operated'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('ball-operated');
update public.questions set question = '[Well Completions, Well Workover and Intervention] Another term for [TERM], small spheres designed to seal perforations that are accepting the most fluid, thereby diverting reservoir treatments to other portions of the target zone. [TERM] are incorporated into the treatment fluid and pumped with it. The effectiveness of this type of mechanical diversion to keep the balls in place is strongly dependent on the differential pressure across the perforation and the geometry of the perforation itself.', accepted_answers = array['ball sealers', 'frac balls']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac balls';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac balls' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('ball sealers'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('ball sealers');
update public.questions set question = '1. (n.) [Drilling Fluids] A chemical whose molecular structure can envelop and hold a certain type of ion in a stable and soluble complex. Divalent cations, such as hardness ions, form stable and soluble complex structures with several types of sequestering chemicals. When held inside the complex, the ions have a limited ability to react with other ions, clays or polymers. Ethylenediamine tetraacetic acid (EDTA) is a well-known [TERM] for the hardness ions, such as Ca+2, and is the reagent solution used in the hardness test protocol published by API. Polyphosphates can also sequester hardness ions. The addition of sodium acid pyrophosphate (SAPP) to a cement-contaminated mud renders the calcium ions essentially nonreactive with clays in the mud. As a side benefit, SAPP also lowers mud pH. Sequestering is not the same as precipitation because sequestering does not form a solid. | 2. (n.) [Well Completions, Drilling Fluids, Well Workover and Intervention] Another term for [TERM], a chemical used to bind metal ions to form a ring structure. [TERM] stabilize or prevent the precipitation of damaging compounds. In the oil field, [TERM] are used in stimulation treatments and for cleaning surface facilities. They are also used to treat or remove scale or weighting agents in reservoir drilling fluids. During acid or scale-removal treatments, various compounds may be dissolved in the treatment fluid. As the acid reacts and the pH increases, reaction products may precipitate as a gelatinous, insoluble mass. Should this occur within the formation matrix, it is almost impossible to remove and permanent permeability damage may occur. [TERM] prevent precipitation by keeping ions in a soluble form until the treatment fluid can be flowed back from the formation during cleanup. Typical oilfield [TERM] include EDTA (ethylenediamine tetraacetic acid), HEDTA (hydroxyethylenediamine triacetic acid), NTA (nitriolotriacetic acid) and citric acid. | 3. (n.) [Enhanced Oil Recovery] Another term for [TERM], a chemical added to an acid to stabilize iron. The injected acid dissolves iron from rust, millscale, iron scales or iron-containing minerals in the formation. Iron can exist as ferric iron [Fe+3] or ferrous iron [Fe+2]. If the iron is not controlled, it will precipitate insoluble products such as ferric hydroxide and, in sour environments, ferrous sulfide [FeS], which will damage the formation. [TERM] associate with iron [Fe+3 or Fe+2] to form soluble complexes. Citric acid, acetic acid and EDTA are effective [TERM] and can be used at temperatures up to 400oF [204oC].', accepted_answers = array['chelating agent', 'sequestering agent']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'chelating agent';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'chelating agent' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('sequestering agent'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('sequestering agent');
update public.questions set question = '1. (n.) [Well Completions, Production Logging] A multiphase flow regime in near-vertical pipes in which large, irregular slugs of gas move up the center of the pipe, usually carrying droplets of oil or water with them. Most of the remaining oil or water flows up along the pipe walls. The flow is relatively chaotic, producing a frothy mixture. Unlike slug flow, neither phase is continuous. The gas slugs are relatively unstable, and take on large, elongated shapes. Also known as [TERM], this flow is an intermediate flow condition between slug flow and mist flow and occurs at relatively high gas velocity. As the gas velocity increases, it changes into annular flow. | 2. (n.) [Production Logging] A multiphase flow regime in near-vertical pipes in which large, irregular slugs of gas move up the center of the pipe, usually carrying droplets of oil or water with them. Most of the remaining oil or water flows up along the pipe walls. Unlike slug flow, neither phase is continuous. The gas slugs are relatively unstable, and take on large, elongated shapes. [TERM] occurs at relatively high gas velocity and is similar to [TERM]. As the gas velocity increases, it changes into annular flow.', accepted_answers = array['churn flow', 'froth flow', 'transition flow']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'churn flow';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'churn flow' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('froth flow', 'transition flow'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('froth flow', 'transition flow');
update public.questions set question = '[Well Completions] A short subassembly used to enable two components with different thread types or sizes to be connected.', accepted_answers = array['cross over', 'crossover']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'crossover';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'crossover' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('cross over'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('cross over');
update public.questions set question = '[Well Completions] A hole or short conduit through which fluids can flow. In equipment applications, a [TERM] is generally made to avoid the buildup of pressure within a nonpressure area, such as may occur in the event of a leak in a pressure housing within a tool assembly.', accepted_answers = array['drain hole', 'drainhole']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'drainhole';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'drainhole' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('drain hole'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('drain hole');
