update public.questions set question = '[Well Completions] A primary recovery mechanism for oil wells containing dissolved and free gas, whereby the energy of the expanding gas is used to drive the oil from the reservoir formation into the wellbore.', accepted_answers = array['gas drive', 'gasdrive']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'gasdrive';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'gasdrive' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas drive'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas drive');
update public.questions set question = '1. (n.) [Geology] Abbreviation for [TERM], a bounding surface in a reservoir above which predominantly gas occurs and below which predominantly oil occurs. Gas and oil are miscible, so the contact between gas and oil is transitional, forming a zone containing a mix of gas and oil. | 2. (n.) [Well Completions] Abbreviation for [TERM], the interface between the gas and oil phases present in a reservoir formation. During the production of a well, the [TERM] may move, resulting in undesirable production conditions such as a high proportion of gas that may be too much for surface processing facilities. Monitoring the gas-oil and oil-water contacts is a key element of good reservoir management practices.', accepted_answers = array['gas-oil contact', 'GOC']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'GOC';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'GOC' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas-oil contact'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('gas-oil contact');
update public.questions set question = '[Well Completions, Shale Gas] A technique to track the propagation of a hydraulic fracture as it advances through a formation. Microseisms are detected, located, and displayed in time for scientists and engineers to approximate the location and propagation of the hydraulic fracture. Software provides modeling, survey design, microseismic detection and location, uncertainty analysis, data integration, and visualization for interpretation. Computer imagery is used to monitor the activity in 3D space relative to the location of the fracturing treatment. The monitored activities are animated to show progressive fracture growth and the subsurface response to pumping variations. When displayed in real time, the microseismic activity allows one to make changes to the stimulation design to ensure optimal reservoir contact. Also known as [TERM], this technique delivers information about the effectiveness of the stimulation of a reservoir that can be used to enhance reservoir development in shale gas completions.', accepted_answers = array['hydraulic fracture monitoring', 'microseismic monitoring']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'microseismic monitoring';
