update public.questions set question = '[Well Completions] A setting or operating method that uses hydraulic force applied through the tubing or running string to activate a downhole tool. In many cases a drop ball, which lands in a profiled seat, will be used to shift the setting or activation mechanism at predetermined pressures.', accepted_answers = array['hydraulic set', 'hydraulic-set']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'hydraulic set';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'hydraulic set' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydraulic-set'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydraulic-set');
update public.questions set question = '[Well Completions, Well Workover and Intervention] A mixture of hydrofluoric acid [HF] and hydrochloric acid [HCl] or organic acid used as the main fluid in a sandstone matrix treatment. Hydrochloric acid or organic acid is mixed with HF to keep the pH low when it spends, thereby preventing detrimental precipitates. The name [TERM] was given to these mixtures because they were originally developed to treat damage from siliceous drilling muds. [TERM] is also called [TERM].', accepted_answers = array['hydrofluoric-hydrochloric acid', 'mud acid']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud acid';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud acid' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydrofluoric-hydrochloric acid'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydrofluoric-hydrochloric acid');
update public.questions set question = '[Drilling, Drilling Fluids, Production Facilities, Well Testing, Well Workover and Intervention, Well Completions] [H2S] An extraordinarily poisonous gas with a molecular formula of H2S. At low concentrations, H2S has the odor of rotten eggs, but at higher, lethal concentrations, it is odorless. H2S is hazardous to workers and a few seconds of exposure at relatively low concentrations can be lethal, but exposure to lower concentrations can also be harmful. The effect of H2S depends on duration, frequency and intensity of exposure as well as the susceptibility of the individual. [TERM] is a serious and potentially lethal hazard, so awareness, detection and monitoring of H2S is essential. Since [TERM] gas is present in some subsurface formations, drilling and other operational crews must be prepared to use detection equipment, personal protective equipment, proper training and contingency procedures in H2S-prone areas. [TERM] is produced during the decomposition of organic matter and occurs with hydrocarbons in some areas. It enters drilling mud from subsurface formations and can also be generated by sulfate-reducing bacteria in stored muds. H2S can cause sulfide-stress-corrosion cracking of metals. Because it is corrosive, H2S production may require costly special production equipment such as stainless steel tubing. Sulfides can be precipitated harmlessly from water muds or oil muds by treatments with the proper sulfide scavenger. H2S is a weak acid, donating two hydrogen ions in neutralization reactions, forming HS- and S-2 ions. In water or water-base muds, the three sulfide species, H2S and HS- and S-2 ions, are in dynamic equilibrium with water and H+ and OH- ions. The percent distribution among the three sulfide species depends on pH. H2S is dominant at low pH, the HS- ion is dominant at mid-range pH and S2 ions dominate at high pH. In this equilibrium situation, sulfide ions revert to H2S if pH falls. Sulfides in water mud and oil mud can be quantitatively measured with the Garrett Gas Train according to procedures set by API.', accepted_answers = array['hydrogen sulfide', 'sulfide stress cracking']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'hydrogen sulfide';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'hydrogen sulfide' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('sulfide stress cracking'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('sulfide stress cracking');
update public.questions set question = '[Well Completions] Abbreviation for [TERM], a passive component installed as part of a well completion to help optimize production by equalizing reservoir inflow along the length of the wellbore. Multiple [TERM] can be installed along the reservoir section of the completion, with each device employing a specific setting to partially choke flow. The resulting arrangement can be used to delay water or gas breakthrough by reducing annular velocity across a selected interval such as the heel of a horizontal well. [TERM] are frequently used with sand screens on openhole completions.', accepted_answers = array['ICD', 'inflow control device']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'ICD';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'ICD' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('inflow control device'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('inflow control device');
update public.questions set question = '[Well Completions] Abbreviation for [TERM], an active component installed as part of a well completion to partially or completely choke flow into a well. [TERM] can be installed along the reservoir section of the completion, with each device typically separated from the next via a packer. Each [TERM] can be controlled from the surface to maintain flow conformance and, as the reservoir depletes, to stop unwanted fluids from entering the wellbore. A permanent downhole cable provides electric and hydraulic conduits to relay commands from the surface to the [TERM].', accepted_answers = array['ICV', 'inflow control valve']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'ICV';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'ICV' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('inflow control valve'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('inflow control valve');
update public.questions set question = '[Well Completions] A type of mechanism commonly used in the setting and unsetting of downhole tools and equipment such as packers. Most conventional downhole tools operate by upward or downward movement, rotation, or a combination of both. The [TERM] profile creates the track for an actuating cam or pin that combines rotation and up or down movement to provide a simple yet reliable means of tool activation.', accepted_answers = array['J slot', 'J-slot']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'J slot';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'J slot' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('J-slot'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('J-slot');
update public.questions set question = '[Well Workover and Intervention, Well Completions] A treatment designed to treat the near-wellbore reservoir formation rather than other areas of the production conduit, such as the casing across the production interval, production tubulars or the perforations. [TERM] treatments include acid, solvent and chemical treatments to improve the permeability of the near-wellbore formation, enhancing the productivity of a well. [TERM] is a process of injecting a fluid into the formation, either an acid or solvent at pressures below the fracturing pressure, to improve the production or injection flow capacity of a well. The goal of a matrix treatment is different in sandstones than in carbonates. In sandstones, matrix treatments restore or improve the natural formation permeability around the wellbore by removing formation damage, by dissolving material plugging the pores or by enlarging the pore spaces. In carbonates, [TERM] creates new, highly conductive channels (wormholes) that bypass damage. Because of these differences, the selection criteria for the treating fluid are also distinct. For sandstone treatments, knowledge of the extent, type of damage, location, origin, reservoir mineralogy (petrographic study) and compatibility of the treating fluid with the formation are especially important. In carbonate treatments, reservoir temperature, pumping rate and fluid type become more significant because these parameters directly affect the reactivity of the treating fluid with the reservoir rock. A sandstone [TERM] treatment is generally composed of a hydrochloric acid [HCl] preflush, a main treating fluid (HCl-HF mixtures) and an overflush (weak acid solution or brine). The treating fluid is maintained under pressure inside the reservoir for a period of time, after which the well is swabbed and returned to production. In carbonate reservoirs, HCl is the most common fluid used. Organic acids such as formic and acetic acid are used in either sandstone or carbonate acidizing, mainly in retarded-acid systems or in high-temperature applications. [TERM] is also called matrix treatment or [TERM].', accepted_answers = array['matrix acidizing', 'matrix stimulation']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'matrix acidizing';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'matrix acidizing' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('matrix stimulation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('matrix stimulation');
update public.questions set question = '1. (vb.) [Drilling] To take apart, disassemble and otherwise prepare to move the rig or blowout preventers. | 2. (n.) [Well Completions] The process of disassembling well-control or pressure-control equipment on the wellhead. Depending on the configuration of the wellhead and casing strings, it may be necessary to [TERM] and nipple-up the blowout preventer (BOP) system as each casing string is run. Antonyms: nipple up, nipple-up', accepted_answers = array['nipple down', 'nipple-down']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'nipple down';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'nipple down' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('nipple-down'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('nipple-down');
update public.questions set question = '1. (vb.) [Drilling] To put together, connect parts and plumbing, or otherwise make ready for use. This term is usually reserved for the installation of a blowout preventer stack. | 2. (n.) [Well Completions] The process of assembling well-control or pressure-control equipment on the wellhead. Antonyms: nipple down, nipple-down', accepted_answers = array['nipple up', 'nipple-up']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'nipple up';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'nipple up' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('nipple-up'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('nipple-up');
update public.questions set question = '[Well Completions] Another term for [TERM], the use of nitrogen gas circulated into the production conduit to displace liquids and reduce the hydrostatic pressure created by the fluid column. Nitrogen lifting is a common technique used to initiate production on a well following workover or overbalanced completion. A coiled tubing string is generally used to apply the treatment, which involves running to depth while pumping high-pressure nitrogen gas. Once the kill-fluid column is unloaded and the well is capable of natural flow, the coiled tubing string is removed and the well is prepared for production.', accepted_answers = array['nitrogen kickoff', 'nitrogen lift']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'nitrogen lift';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'nitrogen lift' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('nitrogen kickoff'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('nitrogen kickoff');
update public.questions set question = '1. (n.) [Well Completions] The calculated maximum flow rate that a system may provide in the absence of restrictions. The term may be qualified as relating to a specific zone, such as a perforated interval, or be used in referring to the production capability of the well. | 2. (n.) [Well Testing] The theoretical flow capacity of gas wells if the bottomhole pressure could be reduced to atmospheric pressure. Test procedures to determine the atmospheric open-flow (AOF) potential were often prescribed by law and enforced by state agencies. The [TERM] capacity of the well was then used to determine the maximum rate that the gas well would be allowed to produce into a pipeline. During that period when there was an excessive amount of gas available for sale, this approach allowed an orderly method of allocating production rights to operators. The methodology is still used in some areas. The test required use of multiple rates, usually three or four, with measurement or calculation of the bottomhole pressure at the end of each flow period. The values of the difference between the square of the average reservoir pressure and the square of the bottomhole pressure were computed for each flow rate. These values were then plotted on the y-axis of a log-log plot versus the rate on the x-axis. The value of the [TERM] is obtained by extrapolating the best straight line to the value of the average reservoir pressure squared minus atmospheric pressure squared, and then reading the corresponding rate off the x-axis.', accepted_answers = array['open flow potential', 'open-flow potential']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'open flow potential';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'open flow potential' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('open-flow potential'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('open-flow potential');
update public.questions set question = '1. (n.) [Drilling] A weak spot in the drillstring. Such a weak spot sometimes is intentionally put into the drillstring so that if tension in the drillstring exceeds a predetermined amount, the [TERM] will part and the rest of the drillstring will be salvageable. A [TERM] is commonly included in fishing strings and drillstem testing equipment, where the fish may be successfully caught by the fishing assembly, but tension to free the fish may prove insurmountable. By having the [TERM] in the hole, the fishing company representative knows where the fishing string will part and what will be needed to latch onto the top of this additional fish. | 2. (n.) [Well Completions, Well Workover and Intervention] Another term for [TERM], a downhole tool that is designed to part under controlled conditions. A [TERM] enables part of the tool string to be left in the wellbore while the running string is retrieved.', accepted_answers = array['release joint', 'safety joint']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'safety joint';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'safety joint' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('release joint'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('release joint');
update public.questions set question = '1. (n.) [Well Completions] Another term for [TERM], a generic name for a tool or device that is used in the placement or setting of downhole equipment such as permanent packers or plugs. The [TERM] can be retrieved after the operation or setting process. In some cases, the [TERM] also is used to retrieve the equipment or tool that has been set in the wellbore. | 2. (n.) [Well Workover and Intervention] A downhole tool used to run and set downhole plugs or similar equipment. The term applies to a range of tools used in workover activities, such as coiled tubing, snubbing or rig-based applications. However, the term is most commonly associated with slickline operations, referring to the tools used to run and set slickline locks, plugs and similar downhole equipment.', accepted_answers = array['running tool', 'setting tool']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'running tool';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'running tool' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('setting tool'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('setting tool');
update public.questions set question = '1. (n.) [Drilling] Also known as [TERM], a telescoping joint at the surface in floating offshore operations that permits vessel heave (vertical motion) while maintaining a riser pipe to the seafloor. As the vessel heaves, the [TERM] telescopes in or out by the same amount so that the riser below the [TERM] is relatively unaffected by vessel motion. | 2. (n.) [Well Completions] Also known as [TERM], a completion component designed to accommodate tubing movement or length changes while maintaining a hydraulic seal between the production conduit and the annulus. The size or length of the [TERM] depends on the wellbore conditions and completion characteristics.', accepted_answers = array['slip joint', 'travel joint']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'slip joint';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'slip joint' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('travel joint'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('travel joint');
update public.questions set question = '[Well Completions] Another term for [TERM], a section of liner that is run from a liner hanger back to the wellhead after the initial liner and hanger system have been installed and cemented. A [TERM] may be required to provide the necessary pressure capacity during a flow-test period or for special treatments, and is typically not cemented in place. In some cases, a [TERM] will be installed as a remedial treatment when the integrity of the intermediate casing string is in doubt.', accepted_answers = array['tieback liner', 'tieback string']::text[] where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'tieback liner';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer = 'tieback liner' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('tieback string'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Completions' and source = 'SLB Glossary' and retired_at is null) and answer in ('tieback string');

-- Well Testing
update public.questions set question = '[Well Testing] Fluid flow in the borehole from one zone into another in response to pressure differences between the zones. Any time the wellbore pressure rises above the average pressure in any zone, [TERM] will occur. Analysis of buildup tests involving [TERM] is either impossible or extremely difficult and usually requires expert input to determine useful information from such tests.', accepted_answers = array['back flow', 'backflow']::text[] where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'backflow';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'backflow' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('back flow'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('back flow');
update public.questions set question = '[Well Testing] Gas-well tests, often required by law, in which one flow rate immediately follows another, with each flow period reaching stabilized flow. The bottomhole pressure at the end of each flow period is used to calculate gas-well deliverability.', accepted_answers = array['flow after flow tests', 'flow-after-flow tests']::text[] where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'flow after flow tests';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'flow after flow tests' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow-after-flow tests'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow-after-flow tests');
update public.questions set question = '[Well Testing] The solution to differential equations treating the well as a vertical line through a porous medium. The solution is nearly identical to the finite-wellbore solution. At very early times during a well test, there is a notable difference in the solutions, but the differences disappear soon after a typical well is opened to flow or shut in for a buildup test, and in practice the differences are masked by wellbore storage.', accepted_answers = array['line source solution', 'line-source solution']::text[] where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'line source solution';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'line source solution' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('line-source solution'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('line-source solution');
update public.questions set question = '1. (n.) [Well Completions] The calculated maximum flow rate that a system may provide in the absence of restrictions. The term may be qualified as relating to a specific zone, such as a perforated interval, or be used in referring to the production capability of the well. | 2. (n.) [Well Testing] The theoretical flow capacity of gas wells if the bottomhole pressure could be reduced to atmospheric pressure. Test procedures to determine the atmospheric open-flow (AOF) potential were often prescribed by law and enforced by state agencies. The [TERM] capacity of the well was then used to determine the maximum rate that the gas well would be allowed to produce into a pipeline. During that period when there was an excessive amount of gas available for sale, this approach allowed an orderly method of allocating production rights to operators. The methodology is still used in some areas. The test required use of multiple rates, usually three or four, with measurement or calculation of the bottomhole pressure at the end of each flow period. The values of the difference between the square of the average reservoir pressure and the square of the bottomhole pressure were computed for each flow rate. These values were then plotted on the y-axis of a log-log plot versus the rate on the x-axis. The value of the [TERM] is obtained by extrapolating the best straight line to the value of the average reservoir pressure squared minus atmospheric pressure squared, and then reading the corresponding rate off the x-axis.', accepted_answers = array['open flow potential', 'open-flow potential']::text[] where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'open flow potential';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer = 'open flow potential' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('open-flow potential'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Testing' and source = 'SLB Glossary' and retired_at is null) and answer in ('open-flow potential');

-- Well Workover and Intervention
update public.questions set question = '[Well Completions, Well Workover and Intervention] Another term for [TERM], small spheres designed to seal perforations that are accepting the most fluid, thereby diverting reservoir treatments to other portions of the target zone. [TERM] are incorporated into the treatment fluid and pumped with it. The effectiveness of this type of mechanical diversion to keep the balls in place is strongly dependent on the differential pressure across the perforation and the geometry of the perforation itself.', accepted_answers = array['ball sealers', 'frac balls']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac balls';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac balls' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('ball sealers'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('ball sealers');
update public.questions set question = '1. (n.) [Drilling Fluids] A chemical whose molecular structure can envelop and hold a certain type of ion in a stable and soluble complex. Divalent cations, such as hardness ions, form stable and soluble complex structures with several types of sequestering chemicals. When held inside the complex, the ions have a limited ability to react with other ions, clays or polymers. Ethylenediamine tetraacetic acid (EDTA) is a well-known [TERM] for the hardness ions, such as Ca+2, and is the reagent solution used in the hardness test protocol published by API. Polyphosphates can also sequester hardness ions. The addition of sodium acid pyrophosphate (SAPP) to a cement-contaminated mud renders the calcium ions essentially nonreactive with clays in the mud. As a side benefit, SAPP also lowers mud pH. Sequestering is not the same as precipitation because sequestering does not form a solid. | 2. (n.) [Well Completions, Drilling Fluids, Well Workover and Intervention] Another term for [TERM], a chemical used to bind metal ions to form a ring structure. [TERM] stabilize or prevent the precipitation of damaging compounds. In the oil field, [TERM] are used in stimulation treatments and for cleaning surface facilities. They are also used to treat or remove scale or weighting agents in reservoir drilling fluids. During acid or scale-removal treatments, various compounds may be dissolved in the treatment fluid. As the acid reacts and the pH increases, reaction products may precipitate as a gelatinous, insoluble mass. Should this occur within the formation matrix, it is almost impossible to remove and permanent permeability damage may occur. [TERM] prevent precipitation by keeping ions in a soluble form until the treatment fluid can be flowed back from the formation during cleanup. Typical oilfield [TERM] include EDTA (ethylenediamine tetraacetic acid), HEDTA (hydroxyethylenediamine triacetic acid), NTA (nitriolotriacetic acid) and citric acid. | 3. (n.) [Enhanced Oil Recovery] Another term for [TERM], a chemical added to an acid to stabilize iron. The injected acid dissolves iron from rust, millscale, iron scales or iron-containing minerals in the formation. Iron can exist as ferric iron [Fe+3] or ferrous iron [Fe+2]. If the iron is not controlled, it will precipitate insoluble products such as ferric hydroxide and, in sour environments, ferrous sulfide [FeS], which will damage the formation. [TERM] associate with iron [Fe+3 or Fe+2] to form soluble complexes. Citric acid, acetic acid and EDTA are effective [TERM] and can be used at temperatures up to 400oF [204oC].', accepted_answers = array['chelating agent', 'sequestering agent']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'chelating agent';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'chelating agent' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('sequestering agent'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('sequestering agent');
update public.questions set question = '[Well Workover and Intervention] Another term for [TERM], a downhole device that enables circulation through the tubing string and associated annulus. As a completion accessory, a [TERM] is included to circulate fluid for well kill or kickoff. [TERM] typically are operated by slickline tools and are generally capable of several opening and closing cycles before requiring service.', accepted_answers = array['circulation valve', 'unloading valve']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'unloading valve';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'unloading valve' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('circulation valve'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('circulation valve');
update public.questions set question = '[Well Workover and Intervention] The removal of wellbore-fill material, such as sand, scale or organic materials, and other debris from the wellbore. Many reservoirs produce some sand or fines that may not be carried to surface in the produced fluid. Accumulations of fill material may eventually increase in concentration within the lower wellbore, possibly restricting production. [TERM] using coiled tubing, snubbing or hydraulic workover techniques are performed routinely.', accepted_answers = array['clean out', 'cleanout']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'cleanout';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'cleanout' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('clean out'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('clean out');
update public.questions set question = '1. (n.) [Drilling] A long, continuous length of pipe wound on a spool. The pipe is straightened prior to pushing into a wellbore and rewound to coil the pipe back onto the transport and storage spool. Depending on the pipe diameter (1 in. to 4-1/2 in.) and the spool size, [TERM] can range from 2,000 ft to 15,000 ft [610 to 4,570 m] or greater length. For more details, The Defining Series: Introduction to [TERM]. | 2. (n.) [Well Workover and Intervention] A generic term relating to the use of a [TERM] string and associated equipment. As a well-intervention method, [TERM] techniques offer several key benefits over alternative well-intervention technologies. The ability to work safely under live well conditions, with a continuous string, enables fluids to be pumped at any time regardless of the position or direction of travel. This is a significant advantage in many applications. Installing an electrical conductor or hydraulic conduit further enhances the capability of a [TERM] string and enables relatively complex intervention techniques to be applied safely. For more details, see The Defining Series: Introduction to [TERM].', accepted_answers = array['coiled tubing', 'CT', 'endless tubing', 'reeled tubing']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'CT';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'CT' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('coiled tubing', 'endless tubing', 'reeled tubing'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('coiled tubing', 'endless tubing', 'reeled tubing');
update public.questions set question = '[Well Workover and Intervention] The process of allowing fluids to flow from the well following a treatment, either in preparation for a subsequent phase of treatment or in preparation for cleanup and returning the well to production.', accepted_answers = array['flow back', 'flowback']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowback';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowback' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow back'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow back');
update public.questions set question = '1. (n.) [Well Workover and Intervention] A device installed in a pump manifold or treating line to measure the fluid flow rate. [TERM] can be used to measure the flow rates of liquid or gas and are available in various configurations and with differing operating principles. | 2. (n.) [Production Logging] A device for measuring in-situ the velocity of fluid flow in a well, usually one completed for production or injection. The most common device is the spinner [TERM], but torque [TERM] and crosscorrelation [TERM] also are used. In the 1940s and 1950s, various other surface-metering techniques were tried, but spinner [TERM] emerged as the most suitable for measuring downhole velocities. Spinner and torque [TERM] measure the average velocity of the fluids crossing the device, while crosscorrelation [TERM] measure the velocity of a particular phase. Although not normally called [TERM], various other techniques measure flow velocity, for example water-flow logs, phase-velocity logs, distributed-temperature logs and even audio measurements. | 3. (n.) [Production Testing] An instrument that measures the flow rate of fluids through a pipeline. There are several types of [TERM], including the differential-pressure meter, orifice meter, positive-displacement meter, vortex meter and multiphase meters.', accepted_answers = array['flow meter', 'flowmeter']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowmeter';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'flowmeter' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow meter'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('flow meter');
update public.questions set question = '[Well Completions, Shale Gas, Well Workover and Intervention] Another term for [TERM], a stimulation treatment routinely performed on oil and gas wells in low-permeability reservoirs. Specially engineered fluids are pumped at high pressure and rate into the reservoir interval to be treated, causing a vertical fracture to open. The wings of the fracture extend away from the wellbore in opposing directions according to the natural stresses within the formation. Proppant, such as grains of sand of a particular size, is mixed with the treatment fluid to keep the fracture open when the treatment is complete. [TERM] creates high-conductivity communication with a large area of formation and bypasses any damage that may exist in the near-wellbore area.', accepted_answers = array['frac job', 'hydraulic fracturing']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac job';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'frac job' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydraulic fracturing'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydraulic fracturing');
update public.questions set question = '1. (n.) [Drilling] An inverted "U" shaped section of rigid piping normally used as a conduit for high-pressure drilling fluid. In particular, the term is applied to a structure that connects the top of a vertical standpipe running up the side of a derrick or mast to a flexible kelly hose that in turn is connected to another [TERM] between the flexible line and the swivel. | 2. (n.) [Well Workover and Intervention] The assembly mounted on a coiled tubing injector head that guides the tubing string as it passes through an arc from the reel into a vertical alignment with the injector-head chains and wellbore. The radius of the guide arch is generally designed to be as large as practicable since the plastic deformation created in the coiled tubing string induces material fatigue in the tube.', accepted_answers = array['goose neck', 'gooseneck']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'gooseneck';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'gooseneck' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('goose neck'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('goose neck');
update public.questions set question = '[Well Workover and Intervention] A squeeze-cementing technique involving the application of treatment pressure that is higher than the fracture pressure of the formation. This procedure may be necessary to force the slurry into microcracks or annuli that surround the wellbore. The characteristics of a fracture are dependent on the fluid flow rate when the fracture is initiated; consequently, [TERM] operations must be conducted with a high degree of control to place the slurry in the desired location.', accepted_answers = array['high pressure squeeze', 'high-pressure squeeze']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'high pressure squeeze';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'high pressure squeeze' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('high-pressure squeeze'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('high-pressure squeeze');
update public.questions set question = '[Well Completions, Well Workover and Intervention] A mixture of hydrofluoric acid [HF] and hydrochloric acid [HCl] or organic acid used as the main fluid in a sandstone matrix treatment. Hydrochloric acid or organic acid is mixed with HF to keep the pH low when it spends, thereby preventing detrimental precipitates. The name [TERM] was given to these mixtures because they were originally developed to treat damage from siliceous drilling muds. [TERM] is also called [TERM].', accepted_answers = array['hydrofluoric-hydrochloric acid', 'mud acid']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud acid';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'mud acid' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydrofluoric-hydrochloric acid'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('hydrofluoric-hydrochloric acid');
update public.questions set question = '[Drilling, Drilling Fluids, Production Facilities, Well Testing, Well Workover and Intervention, Well Completions] [H2S] An extraordinarily poisonous gas with a molecular formula of H2S. At low concentrations, H2S has the odor of rotten eggs, but at higher, lethal concentrations, it is odorless. H2S is hazardous to workers and a few seconds of exposure at relatively low concentrations can be lethal, but exposure to lower concentrations can also be harmful. The effect of H2S depends on duration, frequency and intensity of exposure as well as the susceptibility of the individual. [TERM] is a serious and potentially lethal hazard, so awareness, detection and monitoring of H2S is essential. Since [TERM] gas is present in some subsurface formations, drilling and other operational crews must be prepared to use detection equipment, personal protective equipment, proper training and contingency procedures in H2S-prone areas. [TERM] is produced during the decomposition of organic matter and occurs with hydrocarbons in some areas. It enters drilling mud from subsurface formations and can also be generated by sulfate-reducing bacteria in stored muds. H2S can cause sulfide-stress-corrosion cracking of metals. Because it is corrosive, H2S production may require costly special production equipment such as stainless steel tubing. Sulfides can be precipitated harmlessly from water muds or oil muds by treatments with the proper sulfide scavenger. H2S is a weak acid, donating two hydrogen ions in neutralization reactions, forming HS- and S-2 ions. In water or water-base muds, the three sulfide species, H2S and HS- and S-2 ions, are in dynamic equilibrium with water and H+ and OH- ions. The percent distribution among the three sulfide species depends on pH. H2S is dominant at low pH, the HS- ion is dominant at mid-range pH and S2 ions dominate at high pH. In this equilibrium situation, sulfide ions revert to H2S if pH falls. Sulfides in water mud and oil mud can be quantitatively measured with the Garrett Gas Train according to procedures set by API.', accepted_answers = array['hydrogen sulfide', 'sulfide stress cracking']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'hydrogen sulfide';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'hydrogen sulfide' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('sulfide stress cracking'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('sulfide stress cracking');
update public.questions set question = '[Well Workover and Intervention, Well Completions] A treatment designed to treat the near-wellbore reservoir formation rather than other areas of the production conduit, such as the casing across the production interval, production tubulars or the perforations. [TERM] treatments include acid, solvent and chemical treatments to improve the permeability of the near-wellbore formation, enhancing the productivity of a well. [TERM] is a process of injecting a fluid into the formation, either an acid or solvent at pressures below the fracturing pressure, to improve the production or injection flow capacity of a well. The goal of a matrix treatment is different in sandstones than in carbonates. In sandstones, matrix treatments restore or improve the natural formation permeability around the wellbore by removing formation damage, by dissolving material plugging the pores or by enlarging the pore spaces. In carbonates, [TERM] creates new, highly conductive channels (wormholes) that bypass damage. Because of these differences, the selection criteria for the treating fluid are also distinct. For sandstone treatments, knowledge of the extent, type of damage, location, origin, reservoir mineralogy (petrographic study) and compatibility of the treating fluid with the formation are especially important. In carbonate treatments, reservoir temperature, pumping rate and fluid type become more significant because these parameters directly affect the reactivity of the treating fluid with the reservoir rock. A sandstone [TERM] treatment is generally composed of a hydrochloric acid [HCl] preflush, a main treating fluid (HCl-HF mixtures) and an overflush (weak acid solution or brine). The treating fluid is maintained under pressure inside the reservoir for a period of time, after which the well is swabbed and returned to production. In carbonate reservoirs, HCl is the most common fluid used. Organic acids such as formic and acetic acid are used in either sandstone or carbonate acidizing, mainly in retarded-acid systems or in high-temperature applications. [TERM] is also called matrix treatment or [TERM].', accepted_answers = array['matrix acidizing', 'matrix stimulation']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'matrix acidizing';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'matrix acidizing' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('matrix stimulation'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('matrix stimulation');
update public.questions set question = '1. (n.) [Drilling] A weak spot in the drillstring. Such a weak spot sometimes is intentionally put into the drillstring so that if tension in the drillstring exceeds a predetermined amount, the [TERM] will part and the rest of the drillstring will be salvageable. A [TERM] is commonly included in fishing strings and drillstem testing equipment, where the fish may be successfully caught by the fishing assembly, but tension to free the fish may prove insurmountable. By having the [TERM] in the hole, the fishing company representative knows where the fishing string will part and what will be needed to latch onto the top of this additional fish. | 2. (n.) [Well Completions, Well Workover and Intervention] Another term for [TERM], a downhole tool that is designed to part under controlled conditions. A [TERM] enables part of the tool string to be left in the wellbore while the running string is retrieved.', accepted_answers = array['release joint', 'safety joint']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'safety joint';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'safety joint' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('release joint'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('release joint');
update public.questions set question = '1. (n.) [Well Completions] Another term for [TERM], a generic name for a tool or device that is used in the placement or setting of downhole equipment such as permanent packers or plugs. The [TERM] can be retrieved after the operation or setting process. In some cases, the [TERM] also is used to retrieve the equipment or tool that has been set in the wellbore. | 2. (n.) [Well Workover and Intervention] A downhole tool used to run and set downhole plugs or similar equipment. The term applies to a range of tools used in workover activities, such as coiled tubing, snubbing or rig-based applications. However, the term is most commonly associated with slickline operations, referring to the tools used to run and set slickline locks, plugs and similar downhole equipment.', accepted_answers = array['running tool', 'setting tool']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'running tool';
update public.session_questions set question_id = (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'running tool' order by id limit 1) where question_id in (select id from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('setting tool'));
delete from public.questions where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer in ('setting tool');
update public.questions set question = '[Well Workover and Intervention] Another term for [TERM], the process of removing sand or similar fill from a wellbore. Many wells produce sand that may accumulate and restrict production if not removed from the wellbore by the production fluid. Coiled tubing and snubbing units are routinely used for sand-cleanout operations, enabling the well condition to be treated without removing the completion equipment or even killing the well.', accepted_answers = array['sand cleanout', 'sand lifting']::text[] where topic_id in (select id from public.topics where name = 'Well Workover and Intervention' and source = 'SLB Glossary' and retired_at is null) and answer = 'sand lifting';
